/// Debug routing logic
#[utoipa::path(
    post,
    path = "/v1/routing/debug",
    request_body = RoutingDebugRequest,
    responses(
        (status = 200, description = "Routing debug info", body = RoutingDebugResponse),
        (status = 500, description = "Internal server error", body = ErrorResponse)
    )
)]
pub async fn debug_routing(
    State(state): State<AppState>,
    Extension(claims): Extension<Claims>,
    Json(req): Json<RoutingDebugRequest>,
) -> Result<Json<RoutingDebugResponse>, (StatusCode, Json<ErrorResponse>)> {
    use adapteros_lora_router::{AdapterInfo, CodeFeatures, Router, RouterWeights};

require_any_role(&claims, &[Role::Admin, Role::Operator, Role::Viewer])?;

let combined_context = match req.context {
        Some(ctx) => format!("{} {}", req.prompt, ctx),
        None => req.prompt.clone(),
    };
    let code_features = CodeFeatures::from_context(&combined_context);

let adapters = state
        .db
        .list_adapters_for_tenant(&claims.tenant_id)
        .await
        .map_err(|e| {
            tracing::error!("Failed to list adapters: {}", e);
            (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(
                    ErrorResponse::new("Failed to fetch adapters for routing debug")
                        .with_code("ADAPTER_FETCH_ERROR")
                        .with_string_details(e.to_string()),
                ),
            )
        })?;

let adapter_infos: Vec<AdapterInfo> = adapters
        .iter()
        .map(|adapter| {
            let languages = adapter
                .languages_json
                .as_ref()
                .and_then(|json| serde_json::from_str::<Vec<String>>(json).ok())
                .map(|langs| {
                    langs
                        .into_iter()
                        .filter_map(|lang| language_index(&lang))
                        .collect()
                })
                .unwrap_or_default();

AdapterInfo {
                id: adapter.id.clone(),
                framework: adapter.framework.clone(),
                languages,
                tier: adapter.tier.clone(),
                base_model: adapter.base_model_id.clone(),
                recommended_for_moe: adapter.recommended_for_moe.unwrap_or(true),
                ..Default::default()
            }
        })
        .collect();

let mut router = Router::new_with_weights(RouterWeights::default(), 3, 1.0, 0.02);
    let decision = router
        .route_with_code_features(&code_features, &adapter_infos)
        .map_err(|e| {
            tracing::error!(error = %e, "Failed to compute routing decision for debug");
            (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(
                    ErrorResponse::new("Failed to compute routing decision")
                        .with_code("ROUTING_ERROR")
                        .with_string_details(e.to_string()),
                ),
            )
        })?;
    let explanation = router.explain_score(&code_features.to_vector());

let candidate_scores: HashMap<u16, f32> = decision
        .candidates
        .iter()
        .map(|candidate| (candidate.adapter_idx, candidate.raw_score))
        .collect();

let mut adapter_scores: Vec<AdapterScore> = Vec::new();
    for (idx, adapter) in adapter_infos.iter().enumerate() {
        let is_selected = decision.indices.iter().any(|&i| i as usize == idx);
        let gate_value = if is_selected {
            let position = decision
                .indices
                .iter()
                .position(|&i| i as usize == idx)
                .unwrap_or(0);
            decision.gates_f32()[position] as f64
        } else {
            0.0
        };

adapter_scores.push(AdapterScore {
            adapter_id: adapter.id.clone(),
            score: candidate_scores.get(&(idx as u16)).copied().unwrap_or(0.0) as f64,
            gate_value,
            selected: is_selected,
        });
    }

let detected_lang_idx = code_features
        .lang_one_hot
        .iter()
        .enumerate()
        .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal))
        .map(|(idx, _)| idx);

let language = detected_lang_idx
        .and_then(language_from_index)
        .map(|s| s.to_string());

let frameworks: Vec<String> = code_features.framework_prior.keys().cloned().collect();

let selected_adapters: Vec<String> = decision
        .indices
        .iter()
        .filter_map(|&idx| adapter_infos.get(idx as usize).map(|a| a.id.clone()))
        .collect();

Ok(Json(RoutingDebugResponse {
        features: FeatureVector {
            language,
            frameworks,
            symbol_hits: code_features.symbol_hits as i32,
            path_tokens: code_features.path_tokens.clone(),
            verb: format!("{:?}", code_features.prompt_verb),
        },
        adapter_scores,
        selected_adapters,
        explanation: format!(
            "Router selected {} adapters with entropy {:.3}. {}",
            decision.indices.len(),
            decision.entropy,
            explanation.format()
        ),
    }))
}

let db_url = get_db_url(db_path.as_ref());
    let mut db = Db::connect(&db_url)
        .await
        .context("Failed to connect to database")?;

// Ensure auth session compatibility (creates compatibility view if needed).
    db.resolve_session_table().await?;

let domains = if adapters_only {
        vec![MigrationDomain::Adapters]
    } else if tenants_only {
        vec![MigrationDomain::Tenants]
    } else if stacks_only {
        vec![MigrationDomain::Stacks]
    } else {
        parse_domains(domains.as_deref())?
    };

// Ensure KV backend is attached
    if !db.has_kv_backend() {
        output.info(format!("Attaching KV backend from: {}", kv_path.display()));
        db.init_kv_backend(&kv_path)
            .context("Failed to attach KV backend")?;
    }

if repair {
        output.info("Repair requested: re-migrating selected domains from SQL to KV");
        let opts = MigrationOptions {
            batch_size: 200,
            dry_run: false,
            tenant_filter: None,
            checkpoint: None,
        };
        let (results, _) = db
            .migrate_domains(&domains, &opts)
            .await
            .context("Repair migration failed")?;
        for (domain, stats) in &results {
            output.info(format!(
                "[repair:{}] migrated={}, failed={}, skipped={}",
                domain.label(),
                stats.migrated,
                stats.failed,
                stats.skipped
            ));
        }
    }

let mode = db.storage_mode();
    output.info(format!("Current mode: {}", mode));
    output.info("");

let mut issues = Vec::new();
    if adapters_only && !tenants_only && !stacks_only {
        issues.extend(db.diff_adapters().await?);
    } else if tenants_only && !adapters_only && !stacks_only {
        issues.extend(db.diff_tenants().await?);
    } else if stacks_only && !adapters_only && !tenants_only {
        issues.extend(db.diff_stacks().await?);
    } else {
        // Domain-selectable sweep
        for domain in &domains {
            match domain {
                MigrationDomain::Adapters => issues.extend(db.diff_adapters().await?),
                MigrationDomain::Tenants => issues.extend(db.diff_tenants().await?),
                MigrationDomain::Stacks => issues.extend(db.diff_stacks().await?),
                MigrationDomain::Plans => issues.extend(db.diff_plans().await?),
                MigrationDomain::AuthSessions => issues.extend(db.diff_auth_sessions().await?),
                MigrationDomain::RuntimeSessions => {
                    issues.extend(db.diff_runtime_sessions().await?)
                }
                MigrationDomain::RagArtifacts => {
                    issues.extend(db.diff_documents().await?);
                    issues.extend(db.diff_collections().await?);
                    issues.extend(db.diff_collection_links().await?);
                }
                MigrationDomain::PolicyAudit => issues.extend(db.diff_policy_audit().await?),
                MigrationDomain::TrainingJobs => issues.extend(db.diff_training_jobs().await?),
                MigrationDomain::ChatSessions => issues.extend(db.diff_chat_sessions().await?),
            }
        }
    }

if !issues.is_empty() {
        global_kv_metrics().record_drift_detected();
        if fail_on_drift {
            output.error("Drift detected");
            // Still print issues below
        }
    }

let kv_snapshot = global_kv_metrics().snapshot();
    let degradation_reason = db.degradation_reason();
    let degraded = db.is_degraded();

let issues_for_json = issues.clone();

if output.is_json() {
        let report = VerifyReport {
            drift: issues_for_json.len(),
            drift_events: kv_snapshot.drift_detections_total,
            fallback: kv_snapshot.fallback_operations_total,
            errors: kv_snapshot.errors_total,
            degraded,
            degradation_reason,
            kv_metrics: kv_snapshot,
            issues: issues_for_json,
        };
        output.json(&report)?;
    } else {
        output.info(format!(
            "Dual-write lag ms (avg/p95/max, samples={}): {:.1}/{:.1}/{}",
            kv_snapshot.dual_write_lag_samples,
            kv_snapshot.dual_write_lag_avg_ms,
            kv_snapshot.dual_write_lag_p95_ms,
            kv_snapshot.dual_write_lag_max_ms
        ));
        if issues.is_empty() {
            output.success("No discrepancies detected between SQL and KV");
        } else {
            output.info("Discrepancies detected:");
            for issue in &issues {
                output.info(format!(
                    "- [{domain}] {id} :: {field} sql={sql} kv={kv}",
                    domain = issue.domain,
                    id = issue.id,
                    field = issue.field,
                    sql = issue.sql_value,
                    kv = issue.kv_value
                ));
            }
        }
    }

if fail_on_drift && !issues.is_empty() {
        return Err(anyhow::anyhow!("Drift detected").into());
    }

output.success("Verification complete");

Ok(())
}

