/// Prevent entering KV-only mode when unsupported domains remain.
    ///
    /// Falls back to KvPrimary and records degradation reason for observability.
    pub fn enforce_kv_only_guard(&mut self) -> Result<()> {
        if !self.storage_mode.is_kv_only() {
            return Ok(());
        }

let coverage = kv_coverage_summary();
        if coverage.unsupported_domains.is_empty() {
            // Also downgrade if KV health signals fallbacks/errors while in kv_only.
            let snapshot = crate::kv_metrics::global_kv_metrics().snapshot();
            if snapshot.fallback_operations_total == 0 && snapshot.errors_total == 0 {
                return Ok(());
            }

let reason = format!(
                "KV-only downgraded: fallbacks={} errors={}",
                snapshot.fallback_operations_total, snapshot.errors_total
            );

if self.pool.is_none() {
                return Err(AosError::Config(reason));
            }

warn!(
                event = crate::constants::DEGRADATION_EVENT_KV_UNSUPPORTED,
                fallback_mode = "kv_primary",
                fallbacks = snapshot.fallback_operations_total,
                errors = snapshot.errors_total,
                "KV-only mode degraded due to KV fallbacks/errors"
            );

self.storage_mode = StorageMode::KvPrimary;
            self.mark_degraded(reason);
            return Ok(());
        }

let reason = format!(
            "KV-only blocked: missing KV coverage for {}",
            coverage.unsupported_domains.join(", ")
        );

// If we would downgrade but have no SQL pool, bail out to avoid panics on pool()
        if self.pool.is_none() {
            return Err(AosError::Config(reason));
        }

warn!(
            event = crate::constants::DEGRADATION_EVENT_KV_UNSUPPORTED,
            fallback_mode = "kv_primary",
            missing = ?coverage.unsupported_domains,
            "KV-only mode rejected; coverage incomplete"
        );

// Fall back to KvPrimary to preserve SQL fallback while keeping KV writes
        self.storage_mode = StorageMode::KvPrimary;
        self.mark_degraded(reason);
        Ok(())
    }

/// Get a StackKvRepository if KV writes are enabled
    fn get_stack_kv_repo(&self) -> Option<stacks_kv::StackKvRepository> {
        if self.storage_mode().write_to_kv() {
            self.kv_backend().map(|kv| {
                let kv_backend: Arc<dyn kv_backend::KvBackend> = kv.clone();
                stacks_kv::StackKvRepository::new(kv_backend)
            })
        } else {
            None
        }
    }

/// Insert a new adapter stack
    pub async fn insert_stack(&self, req: &CreateStackRequest) -> Result<String> {
        let id = uuid::Uuid::new_v4().to_string();
        let adapter_ids_json =
            serde_json::to_string(&req.adapter_ids).map_err(|e| AosError::Serialization(e))?;
        let workflow_type = req.workflow_type.as_deref().unwrap_or("Parallel");
        let description = req.description.as_deref().unwrap_or("");

// Validate required fields
    let required_fields = vec![
        "vocab_size",
        "hidden_size",
        "num_layers",
        "num_attention_heads",
        "intermediate_size",
    ];

for field in required_fields {
        if config.get(field).is_none() {
            return Err(AosError::Validation(format!(
                "config.json missing required field: {}",
                field
            )));
        }
    }

// Validate field types and ranges
    if let Some(vocab_size) = config.get("vocab_size") {
        if let Some(size) = vocab_size.as_u64() {
            if size == 0 || size > 200_000 {
                return Err(AosError::Validation(format!(
                    "config.json vocab_size {} is out of reasonable range (1-200,000)",
                    size
                )));
            }
        } else {
            return Err(AosError::Validation(
                "config.json vocab_size must be a positive integer".to_string(),
            ));
        }
    }

if let Some(hidden_size) = config.get("hidden_size") {
        if let Some(size) = hidden_size.as_u64() {
            if !(128..=16384).contains(&size) {
                return Err(AosError::Validation(format!(
                    "config.json hidden_size {} is out of reasonable range (128-16,384)",
                    size
                )));
            }
        } else {
            return Err(AosError::Validation(
                "config.json hidden_size must be a positive integer".to_string(),
            ));
        }
    }

if let Some(num_layers) = config.get("num_layers") {
        if let Some(layers) = num_layers.as_u64() {
            if layers == 0 || layers > 256 {
                return Err(AosError::Validation(format!(
                    "config.json num_layers {} is out of reasonable range (1-256)",
                    layers
                )));
            }
        } else {
            return Err(AosError::Validation(
                "config.json num_layers must be a positive integer".to_string(),
            ));
        }
    }

if let Some(num_heads) = config.get("num_attention_heads") {
        if let Some(heads) = num_heads.as_u64() {
            if heads == 0 || heads > 128 {
                return Err(AosError::Validation(format!(
                    "config.json num_attention_heads {} is out of reasonable range (1-128)",
                    heads
                )));
            }
        } else {
            return Err(AosError::Validation(
                "config.json num_attention_heads must be a positive integer".to_string(),
            ));
        }
    }

Ok(())
}

/// Validate tokenizer configuration JSON with semantic checks
///
/// Performs validation for tokenizer.json files to ensure they contain
/// valid tokenizer configuration.
///
/// # Arguments
/// * `content` - The JSON content to validate
///
/// # Returns
/// * `Ok(())` if content is valid tokenizer config JSON
/// * `Err(AosError::Validation)` if content is invalid
pub fn validate_tokenizer_config_json(content: &str) -> Result<()> {
    // First do basic JSON validation
    validate_json_content(content, "tokenizer.json")?;

// Parse as generic JSON
    let config: serde_json::Value = serde_json::from_str(content)
        .map_err(|e| AosError::Validation(format!("Failed to parse tokenizer.json: {}", e)))?;

// Tokenizers should have some basic structure
    // At minimum, check for common tokenizer fields
    let has_common_fields = config.get("model").is_some()
        || config.get("vocab").is_some()
        || config.get("merges").is_some()
        || config.get("added_tokens").is_some();

if !has_common_fields {
        return Err(AosError::Validation(
            "tokenizer.json does not appear to contain valid tokenizer configuration".to_string(),
        ));
    }

