//! Import bundle

use crate::output::OutputWriter;
use adapteros_artifacts::bundle;
use adapteros_core::B3Hash;
use adapteros_db::Db;
use adapteros_platform::common::PlatformUtils;
use anyhow::{Context, Result};
use serde::Serialize;
use std::fs;
use std::path::Path;

#[derive(Serialize)]
struct ImportResult {
    artifacts_count: usize,
    location: String,
}

pub async fn run(bundle_path: &Path, verify: bool, output: &OutputWriter) -> Result<()> {
    output.info(format!("Importing bundle: {}", bundle_path.display()));

// Verify bundle if requested
    if verify {
        output.info("Verifying bundle...");
        super::verify::run(bundle_path, output).await?;
    }

// Create temporary directory for extraction
    let temp_root = PlatformUtils::temp_dir();
    fs::create_dir_all(&temp_root).with_context(|| {
        format!(
            "Failed to create adapterOS temp directory {}",
            temp_root.display()
        )
    })?;
    let temp_dir = tempfile::Builder::new()
        .prefix("adapteros-import-")
        .tempdir_in(&temp_root)
        .context("Failed to create temporary directory")?;

output.progress("Extracting bundle");

// Extract bundle
    bundle::extract_bundle(bundle_path, temp_dir.path()).context("Failed to extract bundle")?;

output.progress_done(true);

// Load SBOM to get artifact metadata
    let sbom_path = temp_dir.path().join("sbom.json");
    let sbom_content = fs::read_to_string(&sbom_path).context("Failed to read SBOM file")?;

// Compute SBOM hash for signature context
    let sbom_hash = B3Hash::hash(sbom_content.as_bytes());

// Load bundle signature file (required for cryptographic verification)
    let signature_path = temp_dir.path().join("signature.sig");
    let bundle_signature_b64 = if signature_path.exists() {
        let sig_hex =
            fs::read_to_string(&signature_path).context("Failed to read signature.sig file")?;
        // Convert hex signature to base64 for storage
        let sig_bytes = hex::decode(sig_hex.trim())
            .context("Failed to decode signature hex from signature.sig")?;
        base64::Engine::encode(&base64::engine::general_purpose::STANDARD, &sig_bytes)
    } else {
        return Err(anyhow::anyhow!(
            "Bundle is missing signature.sig file. \
            Imported artifacts require cryptographic signatures for chain-of-custody. \
            Use `aosctl verify bundle` to check bundle integrity before import."
        ));
    };

output.success("Bundle signature file found");

let sbom: serde_json::Value =
        serde_json::from_str(&sbom_content).context("Failed to parse SBOM JSON")?;

let artifacts = sbom["artifacts"]
        .as_array()
        .ok_or_else(|| anyhow::anyhow!("SBOM missing artifacts array"))?;

output.info(format!("Processing {} artifacts", artifacts.len()));

// Connect to database
    let db = Db::connect_env()
        .await
        .context("Failed to connect to database")?;

// Create artifacts directory (CAS storage)
    let cas_dir = Path::new("./artifacts");
    fs::create_dir_all(cas_dir).context("Failed to create artifacts directory")?;

// Import each artifact
    let mut imported_count = 0;
    for artifact in artifacts {
        let path = artifact["path"]
            .as_str()
            .ok_or_else(|| anyhow::anyhow!("Artifact missing path"))?;

let hash = artifact["hash"]
            .as_str()
            .ok_or_else(|| anyhow::anyhow!("Artifact missing hash"))?;

let kind = artifact["kind"]
            .as_str()
            .ok_or_else(|| anyhow::anyhow!("Artifact missing kind"))?;

let artifact_path = temp_dir.path().join(path);
        let content = fs::read(&artifact_path)
            .with_context(|| format!("Failed to read artifact: {}", path))?;

// Copy to CAS storage (hash-addressed)
        let cas_path = cas_dir.join(hash);
        fs::write(&cas_path, &content)
            .with_context(|| format!("Failed to write to CAS: {}", hash))?;

// Use the bundle signature for artifact provenance
        // The bundle signature signs the SBOM which contains the artifact hash,
        // providing cryptographic chain-of-custody for all artifacts in the bundle.
        let artifact_signature = &bundle_signature_b64;

// Get size
        let size_bytes = content.len() as i64;

return Ok((quant_type, group_size, bits));
            }
        }

// Default to int4 block quantization (most common for MLX models)
        debug!("Using default quantization: int4_block, group_size=128, bits=4");
        Ok(("int4_block".to_string(), 128, 4))
    }

/// Validate model configuration against manifest
    pub fn validate_manifest(&self, manifest: &adapteros_manifest::ManifestV3) -> Result<()> {
        // Check model name matches
        if self.config.name != manifest.base.model_id {
            return Err(AosError::InvalidManifest(format!(
                "Model name mismatch: {} != {}",
                self.config.name, manifest.base.model_id
            )));
        }

// Check architecture matches
        if self.config.architecture != manifest.base.arch {
            return Err(AosError::InvalidManifest(format!(
                "Architecture mismatch: {} != {}",
                self.config.architecture, manifest.base.arch
            )));
        }

// Check vocabulary size
        if self.config.vocab_size != manifest.base.vocab_size {
            return Err(AosError::InvalidManifest(format!(
                "Vocabulary size mismatch: {} != {}",
                self.config.vocab_size, manifest.base.vocab_size
            )));
        }

// Check hidden dimension
        if self.config.hidden_size != manifest.base.hidden_dim {
            return Err(AosError::InvalidManifest(format!(
                "Hidden dimension mismatch: {} != {}",
                self.config.hidden_size, manifest.base.hidden_dim
            )));
        }

// Check number of layers
        if self.config.num_hidden_layers != manifest.base.n_layers {
            return Err(AosError::InvalidManifest(format!(
                "Number of layers mismatch: {} != {}",
                self.config.num_hidden_layers, manifest.base.n_layers
            )));
        }

// Check number of attention heads
        if self.config.num_attention_heads != manifest.base.n_heads {
            return Err(AosError::InvalidManifest(format!(
                "Number of attention heads mismatch: {} != {}",
                self.config.num_attention_heads, manifest.base.n_heads
            )));
        }

Ok(())
    }

/// Calculate LoRA memory requirements for adapters
    pub fn calculate_lora_memory(
        &self,
        adapters: &[adapteros_manifest::Adapter],
    ) -> Result<Vec<u64>> {
        let mut memory_requirements = Vec::new();

for adapter in adapters {
            let memory = self.calculate_adapter_memory(adapter)?;
            memory_requirements.push(memory);
        }

Ok(memory_requirements)
    }

/// Calculate memory requirement for a single adapter
    fn calculate_adapter_memory(&self, adapter: &adapteros_manifest::Adapter) -> Result<u64> {
        let rank = adapter.rank as u64;
        let hidden_size = self.config.hidden_size as u64;
        let intermediate_size = self.config.intermediate_size as u64;
        let num_layers = self.config.num_hidden_layers as u64;

// Calculate parameters per layer
        let attention_params = rank * (hidden_size + hidden_size); // Q, K, V, O
        let mlp_params = rank * (hidden_size + intermediate_size + intermediate_size + hidden_size); // gate, up, down

let params_per_layer = attention_params + mlp_params;
        let total_params = params_per_layer * num_layers;

// Convert to bytes (fp16 = 2 bytes per parameter)
        let memory_bytes = total_params * 2;

Ok(memory_bytes)
    }

/// Get GQA configuration
    pub fn get_gqa_config(&self) -> GqaConfig {
        GqaConfig {
            num_attention_heads: self.config.num_attention_heads,
            num_key_value_heads: self.config.num_key_value_heads,
            head_dim: self.config.hidden_size / self.config.num_attention_heads,
            kv_width: self.config.num_key_value_heads
                * (self.config.hidden_size / self.config.num_attention_heads),
        }
    }

/// Get RoPE configuration
    pub fn get_rope_config(&self) -> RoPEConfig {
        RoPEConfig {
            theta: self.config.rope_theta,
            scaling_factor: self.config.rope_scaling_factor,
            max_position_embeddings: self.config.max_position_embeddings,
        }
    }
}

