pub async fn latest_metadata(&self, repo_id: &str) -> Result<Option<CodeGraphMetadataKv>> {
        let prefix = format!("repo-metadata-latest:{repo_id}:");
        let mut entries = Vec::new();
        let keys = self
            .backend
            .scan_prefix(&prefix)
            .await
            .map_err(|e| AosError::Database(format!("KV scan metadata failed: {e}")))?;
        for key in keys {
            if let Some(id) = key.split(':').next_back() {
                if let Some(meta) = self.get_metadata(id).await? {
                    entries.push(meta);
                }
            }
        }

entries.sort_by(|a, b| {
            b.created_at
                .cmp(&a.created_at)
                .then_with(|| b.id.cmp(&a.id))
        });
        Ok(entries.into_iter().next())
    }

pub async fn get_metadata(&self, id: &str) -> Result<Option<CodeGraphMetadataKv>> {
        let Some(bytes) = self
            .backend
            .get(&Self::metadata_key(id))
            .await
            .map_err(|e| AosError::Database(format!("KV get metadata failed: {e}")))?
        else {
            return Ok(None);
        };

serde_json::from_slice(&bytes)
            .map_err(AosError::Serialization)
            .map(Some)
    }

pub async fn create_scan_job(&self, job: &ScanJobKv) -> Result<()> {
        let bytes = serde_json::to_vec(job).map_err(AosError::Serialization)?;
        self.backend
            .set(&Self::scan_job_key(&job.id), bytes)
            .await
            .map_err(|e| AosError::Database(format!("KV store scan job failed: {e}")))?;

self.backend
            .set(
                &Self::scan_job_repo_index(&job.repo_id, &job.started_at, &job.id),
                job.id.as_bytes().to_vec(),
            )
            .await
            .map_err(|e| AosError::Database(format!("KV set scan job index failed: {e}")))?;
        Ok(())
    }

pub async fn update_scan_job(
        &self,
        job_id: &str,
        status: &str,
        stage: Option<&str>,
        progress_pct: i32,
        error_message: Option<&str>,
    ) -> Result<()> {
        if let Some(mut job) = self.get_scan_job(job_id).await? {
            job.status = status.to_string();
            job.current_stage = stage.map(|s| s.to_string());
            job.progress_pct = progress_pct;
            job.error_message = error_message.map(|s| s.to_string());
            if status == "completed" || status == "failed" {
                job.completed_at = Some(Self::now_ts());
            }
            self.create_scan_job(&job).await?;
        }
        Ok(())
    }

pub async fn get_scan_job(&self, job_id: &str) -> Result<Option<ScanJobKv>> {
        let Some(bytes) = self
            .backend
            .get(&Self::scan_job_key(job_id))
            .await
            .map_err(|e| AosError::Database(format!("KV get scan job failed: {e}")))?
        else {
            return Ok(None);
        };
        serde_json::from_slice(&bytes)
            .map_err(AosError::Serialization)
            .map(Some)
    }

pub async fn list_scan_jobs(&self, repo_id: &str, limit: i32) -> Result<Vec<ScanJobKv>> {
        let prefix = format!("scan-job-repo:{repo_id}:");
        let mut jobs = Vec::new();
        let keys = self
            .backend
            .scan_prefix(&prefix)
            .await
            .map_err(|e| AosError::Database(format!("KV scan scan_jobs failed: {e}")))?;
        for key in keys {
            if let Some(id) = key.split(':').next_back() {
                if let Some(job) = self.get_scan_job(id).await? {
                    jobs.push(job);
                }
            }
        }

jobs.sort_by(|a, b| {
            b.started_at
                .cmp(&a.started_at)
                .then_with(|| b.id.cmp(&a.id))
        });
        jobs.truncate(limit.max(0) as usize);
        Ok(jobs)
    }

fn now_ts() -> String {
        chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string()
    }
}

//! Background reconciler to keep storage and DB metadata in sync.

use std::collections::HashSet;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Duration;
use tracing::{debug, error};

use adapteros_core::B3Hash;
use adapteros_db::NewStorageIssue;
use adapteros_storage::FsByteStorage;
use tokio::fs;
use tokio::time::sleep;
use walkdir::WalkDir;

use crate::handlers::datasets::{
    resolve_dataset_root, resolve_dataset_root_lenient_from_strings, ENV_DATASETS_DIR,
};
use crate::state::AppState;

#[derive(Clone)]
pub struct StorageReconciler {
    state: Arc<AppState>,
}

impl StorageReconciler {
    pub fn new(state: Arc<AppState>) -> Self {
        Self { state }
    }

fn store(&self) -> anyhow::Result<FsByteStorage> {
        let cfg = self
            .state
            .config
            .read()
            .map_err(|_| anyhow::anyhow!("Config lock poisoned in storage reconciler"))?;
        let config_root = if cfg.paths.datasets_root.is_empty() {
            None
        } else {
            Some(cfg.paths.datasets_root.clone())
        };
        let env_root = std::env::var(ENV_DATASETS_DIR).ok();
        let datasets_root = resolve_dataset_root_lenient_from_strings(env_root, config_root)?;
        Ok(FsByteStorage::new(
            datasets_root,
            cfg.paths.adapters_root.clone().into(),
        ))
    }

pub async fn run_once(&self) {
        let store = match self.store() {
            Ok(s) => s,
            Err(e) => {
                error!(error = %e, "Storage reconciler: failed to initialize storage");
                return;
            }
        };

if let Err(e) = self.check_dataset_versions(&store).await {
            error!(error = %e, "Storage reconciler: dataset version check failed");
        }

if let Err(e) = self.check_adapter_versions(&store).await {
            error!(error = %e, "Storage reconciler: adapter version check failed");
        }

if let Err(e) = self.detect_orphans(&store).await {
            error!(error = %e, "Storage reconciler: orphan scan failed");
        }
    }

async fn check_dataset_versions(&self, _store: &FsByteStorage) -> adapteros_core::Result<()> {
        let versions = self
            .state
            .db
            .list_all_dataset_versions()
            .await
            .unwrap_or_default();
        debug!(count = versions.len(), "Reconciling dataset versions");

for v in versions {
            let path = PathBuf::from(&v.storage_path);
            let tenant_id = v.tenant_id.clone();
            if !path.exists() {
                let severity = if v.soft_deleted_at.is_some() {
                    "info"
                } else {
                    "error"
                };
                self.record_issue(NewStorageIssue {
                    tenant_id: tenant_id.as_deref(),
                    owner_type: "dataset_version",
                    owner_id: &v.dataset_id,
                    version_id: Some(&v.id),
                    issue_type: "missing_bytes",
                    severity,
                    location: path.to_string_lossy().as_ref(),
                    details: Some("Dataset version file missing"),
                })
                .await?;
                continue;
            }

let bytes = fs::read(&path).await.map_err(|e| {
                adapteros_core::AosError::Io(format!(
                    "Failed to read dataset {}: {}",
                    path.display(),
                    e
                ))
            })?;
            let hash = B3Hash::hash(&bytes).to_hex();
            if hash != v.hash_b3 {
                self.record_issue(NewStorageIssue {
                    tenant_id: tenant_id.as_deref(),
                    owner_type: "dataset_version",
                    owner_id: &v.dataset_id,
                    version_id: Some(&v.id),
                    issue_type: "hash_mismatch",
                    severity: "error",
                    location: path.to_string_lossy().as_ref(),
                    details: Some("Dataset version hash mismatch"),
                })
                .await?;
            }
        }

Ok(())
    }

async fn check_adapter_versions(&self, __store: &FsByteStorage) -> adapteros_core::Result<()> {
        let versions = self
            .state
            .db
            .list_all_adapter_versions()
            .await
            .unwrap_or_default();
        debug!(count = versions.len(), "Reconciling adapter versions");

for v in versions {
            let Some(path_str) = &v.aos_path else {
                continue;
            };
            let path = PathBuf::from(path_str);
            if !path.exists() {
                let severity = if v.release_state.eq_ignore_ascii_case("archived") {
                    "info"
                } else {
                    "error"
                };
                self.record_issue(NewStorageIssue {
                    tenant_id: Some(&v.tenant_id),
                    owner_type: "adapter_version",
                    owner_id: &v.repo_id,
                    version_id: Some(&v.id),
                    issue_type: "missing_bytes",
                    severity,
                    location: path.to_string_lossy().as_ref(),
                    details: Some("Adapter artifact missing"),
                })
                .await?;
                continue;
            }

let tenant_id = claims.tenant_id.clone();

// Verify stack exists and belongs to tenant
    let stack = state
        .db
        .get_stack(&tenant_id, &id)
        .await
        .map_err(db_error)?
        .ok_or_else(|| {
            not_found(&format!(
                "Stack with id '{}' not found for tenant '{}'",
                id, tenant_id
            ))
        })?;

// CRITICAL: Validate tenant isolation to prevent cross-tenant access
    validate_tenant_isolation(&claims, &stack.tenant_id)?;

// Get lifecycle history
    let history = state
        .db
        .get_stack_lifecycle_history(&id)
        .await
        .map_err(db_error)?;

let response: Vec<LifecycleHistoryResponse> = history.into_iter().map(Into::into).collect();

Ok(Json(response))
}

/// Get policies assigned to an adapter stack with compliance summary
#[utoipa::path(
    get,
    path = "/v1/adapter-stacks/{id}/policies",
    params(
        ("id" = String, Path, description = "Stack ID")
    ),
    responses(
        (status = 200, description = "Stack policies with compliance info", body = crate::types::StackPoliciesResponse),
        (status = 404, description = "Stack not found"),
        (status = 500, description = "Internal server error")
    )
)]
pub async fn get_stack_policies(
    State(state): State<AppState>,
    Extension(claims): Extension<Claims>,
    Path(id): Path<String>,
) -> Result<Json<crate::types::StackPoliciesResponse>, (StatusCode, Json<ErrorResponse>)> {
    require_permission(&claims, Permission::PolicyView)?;

let tenant_id = claims.tenant_id.clone();

// Verify stack exists and belongs to tenant
    let stack = state
        .db
        .get_stack(&tenant_id, &id)
        .await
        .map_err(db_error)?
        .ok_or_else(|| {
            not_found(&format!(
                "Stack with id '{}' not found for tenant '{}'",
                id, tenant_id
            ))
        })?;

// CRITICAL: Validate tenant isolation to prevent cross-tenant access
    validate_tenant_isolation(&claims, &stack.tenant_id)?;

// Get policy assignments for this stack
    let assignments = state
        .db
        .get_policy_assignments_for_stack(&id)
        .await
        .map_err(db_error)?;

// Convert to detailed assignment info with policy pack details
    let mut assignment_details = Vec::new();
    for assignment in assignments {
        // Get the policy pack details
        let pack = state
            .db
            .get_policy_pack(&assignment.policy_pack_id)
            .await
            .map_err(db_error)?;

let (policy_type, policy_name, version, status) = if let Some(p) = pack {
            (
                p.policy_type.clone(),
                p.description
                    .clone()
                    .unwrap_or_else(|| assignment.policy_pack_id.clone()),
                p.version.clone(),
                p.status.clone(),
            )
        } else {
            (
                "unknown".to_string(),
                assignment.policy_pack_id.clone(),
                "1.0.0".to_string(),
                "active".to_string(),
            )
        };

assignment_details.push(crate::types::PolicyAssignmentDetail {
            id: assignment.id,
            policy_pack_id: assignment.policy_pack_id,
            policy_type,
            policy_name,
            version,
            status,
            enforced: assignment.enforced,
            priority: assignment.priority,
            assigned_at: assignment.assigned_at,
            assigned_by: assignment.assigned_by,
            expires_at: assignment.expires_at,
        });
    }

// Calculate compliance summary
    let compliance_data = state
        .db
        .calculate_stack_compliance(&id, &tenant_id)
        .await
        .map_err(db_error)?;

// Convert db type to API response type
    let compliance = crate::types::StackComplianceSummary {
        overall_score: compliance_data.overall_score,
        status: compliance_data.status,
        by_category: compliance_data
            .by_category
            .into_iter()
            .map(|(k, v)| {
                (
                    k,
                    crate::types::CategoryComplianceScore {
                        score: v.score,
                        passed: v.passed,
                        failed: v.failed,
                    },
                )
            })
            .collect(),
        last_calculated: compliance_data.last_calculated,
    };

// Get recent violations (last 24 hours)
    let violations = state
        .db
        .get_recent_stack_violations(&id, 24)
        .await
        .map_err(db_error)?;

let recent_violations: Vec<crate::types::PolicyViolationSummary> = violations
        .into_iter()
        .map(|v| crate::types::PolicyViolationSummary {
            id: v.id,
            policy_pack_id: v.policy_pack_id,
            severity: v.severity,
            message: v.violation_message,
            detected_at: v.detected_at,
            resolved_at: v.resolved_at,
        })
        .collect();

let now = chrono::Utc::now().to_rfc3339();

if !report.adapters_evicted.is_empty() {
        println!("\nEvicted adapters:");
        for evicted in &report.adapters_evicted {
            println!(
                "  - Adapter {} from {} ({} MB freed)",
                evicted.adapter_id,
                evicted.backend.as_str(),
                evicted.bytes_freed / (1024 * 1024)
            );
            telemetry.emit_eviction(evicted);
        }
    }

let final_stats = manager.get_stats();
    println!("\nFinal Memory Statistics:");
    println!(
        "  Total: {} MB",
        final_stats.total_memory_used / (1024 * 1024)
    );
    println!("  Headroom: {:.2}%", final_stats.headroom_pct);
    println!("  Adapters: {}", final_stats.total_adapter_count);
    println!("  Pinned: {}", final_stats.pinned_adapter_count);

println!("\n=== Scenario 5: Eviction candidates ===\n");

let pinned = vec![1];
    let candidates = tracker.get_eviction_candidates(&pinned);

println!("Eviction candidates (sorted by priority):");
    for (adapter_id, backend, bytes, priority) in &candidates {
        let status = if *priority == f32::MAX {
            "PINNED"
        } else {
            "evictable"
        };
        println!(
            "  - Adapter {} ({}) on {}: {} MB (priority: {:.2}) [{}]",
            adapter_id,
            status,
            backend.as_str(),
            bytes / (1024 * 1024),
            priority,
            status
        );
    }

println!("\n=== Summary ===");
    println!(
        "Total telemetry events emitted: {}",
        telemetry_sink.events.lock().unwrap().len()
    );
    println!("All scenarios completed successfully!");
}

