/// Pre-check TCP port availability before handing it to Axum.
pub fn precheck_tcp_port(addr: SocketAddr) -> Result<(), BindError> {
    match TcpListener::bind(addr) {
        Ok(listener) => drop(listener),
        Err(e) if e.kind() == std::io::ErrorKind::AddrInUse => {
            return Err(BindError::PortInUse {
                port: addr.port(),
                addr,
            });
        }
        Err(e) => return Err(BindError::IoError(e)),
    }
    Ok(())
}

/// Bind and serve the application with graceful shutdown.
///
/// This function:
/// 1. Binds to the specified mode (TCP or UDS)
/// 2. Transitions boot state to ready
/// 3. Serves the application with graceful shutdown
/// 4. Handles coordinated shutdown of all components
///
/// # Arguments
///
/// * `mode` - The binding mode (TCP or UDS)
/// * `app` - The Axum router to serve
/// * `config` - Server configuration including boot state and shutdown coordinator
///
/// # Returns
///
/// Returns `Ok(())` on successful shutdown, or `Err` if binding fails.
///
pub async fn bind_and_serve(
    mode: BindMode,
    app: Router,
    config: ServerBindConfig,
) -> Result<(), BindError> {
    let ServerBindConfig {
        boot_state,
        shutdown_coordinator,
        drain_timeout,
        in_flight_requests,
    } = config;

match mode {
        BindMode::Tcp { addr, display_addr } => {
            info!(addr = %addr, "Starting control plane");
            info!(url = %format!("http://{}:{}/", display_addr.ip(), display_addr.port()), "UI available");
            info!(url = %format!("http://{}:{}/api/", display_addr.ip(), display_addr.port()), "API available");
            warn!("Development mode: TCP binding enabled. Set production_mode=true for UDS-only");

precheck_tcp_port(addr)?;

// Bind first, fail fast if port in use
            let listener = match tokio::net::TcpListener::bind(addr).await {
                Ok(l) => l,
                Err(e) if e.kind() == std::io::ErrorKind::AddrInUse => {
                    return Err(BindError::PortInUse {
                        port: addr.port(),
                        addr,
                    });
                }
                Err(e) => return Err(e.into()),
            };

serve_and_shutdown(
                ServeListener::Tcp(listener),
                app,
                boot_state,
                shutdown_coordinator,
                drain_timeout,
                in_flight_requests,
            )
            .await
        }
        BindMode::Uds { socket_path } => {
            info!(socket_path = %socket_path, "Starting control plane on UDS");
            info!("Production mode enabled - TCP binding disabled per Egress policy");

// Remove existing socket file if present
            let _ = std::fs::remove_file(&socket_path);

// Bind first, fail fast if socket cannot be created
            let listener = match tokio::net::UnixListener::bind(&socket_path) {
                Ok(l) => l,
                Err(e) => {
                    return Err(BindError::SocketCreationFailed {
                        path: socket_path.clone(),
                        reason: e.to_string(),
                    });
                }
            };

serve_and_shutdown(
                ServeListener::Uds(listener),
                app,
                boot_state,
                shutdown_coordinator,
                drain_timeout,
                in_flight_requests,
            )
            .await
        }
    }
}

/// Internal enum to unify TCP and UDS listeners for serving.
enum ServeListener {
    Tcp(tokio::net::TcpListener),
    Uds(tokio::net::UnixListener),
}

/// Load fingerprint from JSON file and verify signature
    pub fn load_verified(
        path: &std::path::Path,
        public_key: &adapteros_crypto::PublicKey,
    ) -> Result<Self> {
        use adapteros_crypto::verify_signature;
        use std::fs;

// Read JSON file
        let json = fs::read_to_string(path)
            .map_err(|e| AosError::Io(format!("Failed to read fingerprint: {}", e)))?;

// Read signature file
        let sig_path = path.with_extension("sig");
        let sig_bytes = fs::read(sig_path)
            .map_err(|e| AosError::Io(format!("Failed to read signature: {}", e)))?;

// Verify signature
        let fingerprint_hash = B3Hash::hash(json.as_bytes());
        let signature = adapteros_crypto::Signature::from_bytes(
            sig_bytes
                .as_slice()
                .try_into()
                .map_err(|_| AosError::Crypto("Invalid signature length".to_string()))?,
        )?;

verify_signature(public_key, fingerprint_hash.as_bytes(), &signature)?;

// Deserialize fingerprint
        serde_json::from_str(&json).map_err(AosError::Serialization)
    }

/// Check if this device matches another
    pub fn matches(&self, other: &DeviceFingerprint) -> bool {
        self.compute_hash().ok() == other.compute_hash().ok()
    }

/// Get a summary string for display
    pub fn summary(&self) -> String {
        format!(
            "{} {} (OS {} build {}, Metal {})",
            self.device_model, self.soc_id, self.os_version, self.os_build, self.metal_family
        )
    }
}

/// Complete metadata for a golden run
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GoldenRunMetadata {
    /// Unique identifier for this golden run
    pub run_id: String,
    /// Control Plane ID
    pub cpid: String,
    /// Plan ID
    pub plan_id: String,
    /// When this golden run was created
    pub created_at: chrono::DateTime<chrono::Utc>,
    /// Toolchain information
    pub toolchain: ToolchainMetadata,
    /// Adapter IDs included in this run
    pub adapters: Vec<String>,
    /// Device fingerprint
    pub device: DeviceFingerprint,
    /// Global seed used for deterministic execution
    pub global_seed: B3Hash,
}

impl GoldenRunMetadata {
    /// Create new golden run metadata
    pub fn new(
        cpid: String,
        plan_id: String,
        toolchain_version: String,
        adapters: Vec<String>,
        global_seed: B3Hash,
    ) -> Self {
        // Generate run ID from components
        let run_id = format!(
            "golden-{}-{}",
            cpid,
            chrono::Utc::now().format("%Y%m%d-%H%M%S")
        );

Self {
            run_id,
            cpid,
            plan_id,
            created_at: chrono::Utc::now(),
            toolchain: ToolchainMetadata {
                rustc_version: toolchain_version,
                metal_version: ToolchainMetadata::detect_metal_version(),
                kernel_hash: ToolchainMetadata::compute_kernel_hash(),
            },
            adapters,
            device: DeviceFingerprint::capture_current().unwrap_or_else(|_| DeviceFingerprint {
                schema_version: 1,
                device_model: "Unknown".to_string(),
                soc_id: "Unknown".to_string(),
                gpu_pci_id: "Unknown".to_string(),
                os_version: "Unknown".to_string(),
                os_build: "Unknown".to_string(),
                metal_family: "Unknown".to_string(),
                gpu_driver_version: "Unknown".to_string(),
                path_hash: B3Hash::hash(b""),
                env_hash: B3Hash::hash(b""),
                cpu_features: vec![],
                firmware_hash: None,
                boot_version_hash: None,
            }),
            global_seed,
        }
    }

/// Check if metadata is compatible with another run
    pub fn compatible_with(&self, other: &GoldenRunMetadata) -> Result<()> {
        if self.cpid != other.cpid {
            return Err(AosError::InvalidCPID(format!(
                "CPID mismatch: {} vs {}",
                self.cpid, other.cpid
            )));
        }

if self.plan_id != other.plan_id {
            return Err(AosError::Plan(format!(
                "Plan ID mismatch: {} vs {}",
                self.plan_id, other.plan_id
            )));
        }

if self.global_seed != other.global_seed {
            return Err(AosError::InvalidHash("Global seed mismatch".to_string()));
        }

if !self.toolchain.matches(&other.toolchain) {
            return Err(AosError::Toolchain(format!(
                "Toolchain mismatch: {} vs {}",
                self.toolchain.summary(),
                other.toolchain.summary()
            )));
        }

if self.adapters != other.adapters {
            return Err(AosError::Validation("Adapter set mismatch".to_string()));
        }

Ok(())
    }

