/// Record router selection results to update activation percentages.
    pub async fn record_router_decision(&self, selected: &[u16]) -> Result<()> {
        let changed = {
            let mut tracker = self.activation_tracker.write();
            tracker.record_decision(selected)
        };

if changed.is_empty() {
            return Ok(());
        }

let mut updates = Vec::new();
        {
            let states = self.states.read();
            for (adapter_idx, pct) in &changed {
                if let Some(record) = states.get(adapter_idx) {
                    updates.push((
                        *adapter_idx,
                        record.adapter_id.clone(),
                        record.state,
                        record.pinned,
                        *pct,
                    ));
                }
            }
        }

if let Some(ref db) = self.db {
            for (_, adapter_id, _, _, pct) in updates.iter().cloned() {
                let db_clone = db.clone();
                spawn_deterministic("Activation pct update".to_string(), async move {
                    if let Err(e) = sqlx::query(
                        "UPDATE adapters SET activation_pct = ?, updated_at = datetime('now') \
                         WHERE adapter_id = ?",
                    )
                    .bind(pct)
                    .bind(&adapter_id)
                    .execute(db_clone.pool())
                    .await
                    {
                        warn!("Failed to update activation_pct for {}: {}", adapter_id, e);
                    }
                });
            }
        }

/// Extract tenant ID from command if present
fn extract_tenant_from_command(command: &Commands) -> Option<String> {
    match command {
        Commands::Serve { tenant, .. } | Commands::Rollback { tenant, .. } => Some(tenant.clone()),
        Commands::Diag { tenant, .. } => tenant.clone(),
        Commands::Repo(commands::repo::RepoCommand::Repo(commands::repo::RepoOps::Create(
            args,
        ))) => Some(args.tenant.clone()),
        Commands::Repo(commands::repo::RepoCommand::Repo(commands::repo::RepoOps::List {
            tenant,
            ..
        })) => Some(tenant.clone()),
        // Tenant extraction for grouped commands is handled by their respective handlers
        _ => None,
    }
}

