/// Validate that model directory exists and contains required files
    ///
    /// Checks for:
    /// - Directory existence and readability
    /// - config.json (required, readable, non-empty, within size limits)
    /// - tokenizer.json (required, readable, non-empty, within size limits)
    /// - weights file (weights.safetensors or model.safetensors, readable, non-empty, within size limits)
    fn validate_model_files(&self, model_path: &str) -> Result<(), String> {
        let path = Path::new(model_path);

let allowed_roots =
            model_allowed_roots().map_err(|e| format!("Failed to resolve model roots: {}", e))?;
        // Canonicalize path for security validation
        let canonical_path = canonicalize_strict_in_allowed_roots(path, &allowed_roots)
            .map_err(|e| format!("Path security validation failed for {}: {}", model_path, e))?;

// Check if path exists
        if !canonical_path.exists() {
            return Err(format!("Model path does not exist: {}", model_path));
        }

// Check if path is a directory
        if !canonical_path.is_dir() {
            return Err(format!("Model path is not a directory: {}", model_path));
        }

// Check directory readability
        if std::fs::metadata(&canonical_path).is_err() {
            return Err(format!("Model directory is not readable: {}", model_path));
        }

let path = canonical_path;

// Validate config.json
        let config_path = path.join("config.json");
        Self::validate_required_file(
            &config_path,
            "config.json",
            model_path,
            Some(self.max_config_size_bytes),
        )?;

// Validate tokenizer.json
        let tokenizer_path = path.join("tokenizer.json");
        Self::validate_required_file(
            &tokenizer_path,
            "tokenizer.json",
            model_path,
            Some(self.max_tokenizer_size_bytes),
        )?;

// Validate weights file (check for either weights.safetensors or model.safetensors)
        let weights_path = path.join("weights.safetensors");
        let model_safetensors_path = path.join("model.safetensors");

let weights_file_exists = weights_path.exists() && weights_path.is_file();
        let model_safetensors_exists =
            model_safetensors_path.exists() && model_safetensors_path.is_file();

if !weights_file_exists && !model_safetensors_exists {
            return Err(format!(
                "Required weights file not found in model directory: {}. Expected either 'weights.safetensors' or 'model.safetensors'",
                model_path
            ));
        }

// Validate the weights file that exists
        if weights_file_exists {
            Self::validate_required_file(
                &weights_path,
                "weights.safetensors",
                model_path,
                Some(self.max_model_size_bytes),
            )?;
        } else {
            Self::validate_required_file(
                &model_safetensors_path,
                "model.safetensors",
                model_path,
                Some(self.max_model_size_bytes),
            )?;
        }

Ok(())
    }

/// Validate that a required file exists, is readable, non-empty, and within size limits
    fn validate_required_file(
        file_path: &Path,
        file_name: &str,
        model_path: &str,
        max_size_bytes: Option<u64>,
    ) -> Result<(), String> {
        // Check existence
        if !file_path.exists() {
            return Err(format!(
                "Required file '{}' not found in model directory: {}",
                file_name, model_path
            ));
        }

// Check it's a file (not a directory)
        if !file_path.is_file() {
            return Err(format!(
                "Required file '{}' exists but is not a file in model directory: {}",
                file_name, model_path
            ));
        }

// Check readability and get metadata
        let metadata = std::fs::metadata(file_path).map_err(|e| {
            format!(
                "Cannot read metadata for '{}' in model directory {}: {}",
                file_name, model_path, e
            )
        })?;

fn acquire(&self) {
        self.active_requests.fetch_add(1, Ordering::Relaxed);
        // Placeholder until real memory tracking is wired in.
        self.current_usage.fetch_add(1, Ordering::Relaxed);
    }

fn would_exceed_limit(&self) -> bool {
        let current = self.current_usage.load(Ordering::Relaxed);
        let active = self.active_requests.load(Ordering::Relaxed) as u64;
        let projected = current.saturating_add(active.saturating_mul(self.max_memory_per_request));

projected > self.max_memory_per_request * 2 // Allow 2x for safety
    }

fn release(&self) {
        self.active_requests.fetch_sub(1, Ordering::Relaxed);
        // In a real implementation, we'd track actual memory usage
        // For now, just decrement a counter
        self.current_usage.fetch_sub(1, Ordering::Relaxed);
    }

fn get_current_usage(&self) -> u64 {
        self.current_usage.load(Ordering::Relaxed)
    }
}

/// CPU time tracker
struct CpuTracker {
    max_cpu_time_per_request: Duration,
    total_cpu_time: AtomicU64,
    request_count: AtomicUsize,
}

/// File descriptor usage tracker
struct FileDescriptorTracker {
    max_usage_percent: f32,
    fd_limit: AtomicU64,
    last_check: AtomicU64,
}

/// Thread pool usage tracker
struct ThreadPoolTracker {
    pool_size: usize,
    max_queue_depth: usize,
    active_threads: AtomicUsize,
    queued_tasks: AtomicUsize,
}

impl CpuTracker {
    fn new(max_cpu_time_per_request: Duration) -> Self {
        Self {
            max_cpu_time_per_request,
            total_cpu_time: AtomicU64::new(0),
            request_count: AtomicUsize::new(0),
        }
    }

fn record_usage(&self, duration: Duration) {
        let duration_ms = duration.as_millis() as u64;
        self.total_cpu_time
            .fetch_add(duration_ms, Ordering::Relaxed);
        self.request_count.fetch_add(1, Ordering::Relaxed);

if duration > self.max_cpu_time_per_request {
            warn!(
                "Request exceeded CPU time limit: {}ms > {}ms",
                duration_ms,
                self.max_cpu_time_per_request.as_millis()
            );
        }
    }

fn get_total_time(&self) -> Duration {
        Duration::from_millis(self.total_cpu_time.load(Ordering::Relaxed))
    }

fn _get_request_count(&self) -> usize {
        self.request_count.load(Ordering::Relaxed)
    }
}

impl FileDescriptorTracker {
    fn new(max_usage_percent: f32) -> Self {
        let fd_limit = get_fd_limit().unwrap_or(1024);
        Self {
            max_usage_percent,
            fd_limit: AtomicU64::new(fd_limit),
            last_check: AtomicU64::new(0),
        }
    }

fn check_limit(&self) -> Result<()> {
        // Only check every 500ms to reduce overhead
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .expect("System time before UNIX epoch")
            .as_millis() as u64;

let last = self.last_check.load(Ordering::Relaxed);
        if now.saturating_sub(last) < 500 {
            return Ok(());
        }
        self.last_check.store(now, Ordering::Relaxed);

let current = get_open_fd_count().unwrap_or(0);
        let limit = self.fd_limit.load(Ordering::Relaxed);

if limit == 0 {
            return Ok(());
        }

let usage_percent = (current as f32 / limit as f32) * 100.0;
        if usage_percent >= self.max_usage_percent {
            return Err(AosError::FileDescriptorExhausted {
                current,
                limit,
                suggestion: "Close idle connections or increase ulimit -n".to_string(),
            });
        }

Ok(())
    }

fn get_usage(&self) -> (u64, u64) {
        let current = get_open_fd_count().unwrap_or(0);
        let limit = self.fd_limit.load(Ordering::Relaxed);
        (current, limit)
    }
}

impl ThreadPoolTracker {
    fn new(pool_size: usize, max_queue_depth: usize) -> Self {
        Self {
            pool_size,
            max_queue_depth,
            active_threads: AtomicUsize::new(0),
            queued_tasks: AtomicUsize::new(0),
        }
    }

fn check_limit(&self) -> Result<()> {
        let active = self.active_threads.load(Ordering::Relaxed);
        let queued = self.queued_tasks.load(Ordering::Relaxed);

if active >= self.pool_size && queued >= self.max_queue_depth {
            return Err(AosError::ThreadPoolSaturated {
                active,
                max: self.pool_size,
                queued,
                estimated_wait_ms: (queued as u64) * 50, // Rough estimate
            });
        }

Ok(())
    }

fn record_task_queued(&self) {
        self.queued_tasks.fetch_add(1, Ordering::Relaxed);
    }

