let query = format!(
            "UPDATE chat_session_categories SET {} WHERE id = ?",
            updates.join(", ")
        );

let mut q = sqlx::query(&query);
        for b in &bindings {
            q = q.bind(b);
        }
        q = q.bind(category_id);

q.execute(self.pool())
            .await
            .map_err(db_err("update category"))?;

Ok(())
    }

