    /// - Have status = 'healthy'
    /// - Have health_status IN ('healthy', 'unknown') or NULL
    /// - Ordered by avg_latency_ms (lowest first)
    ///
    /// This is the preferred method for inference routing as it combines
    /// manifest compatibility, schema compatibility, and tenant isolation.
    pub async fn list_compatible_workers_for_tenant(
        &self,
        manifest_hash: &str,
        tenant_id: &str,
    ) -> Result<Vec<WorkerWithBinding>> {
        use adapteros_core::version::API_SCHEMA_VERSION;

let workers = sqlx::query_as::<_, WorkerWithBinding>(
            "SELECT id, tenant_id, node_id, plan_id, uds_path, pid, status,
                    started_at, last_seen_at, manifest_hash_b3, backend, model_hash_b3,
                    capabilities_json, schema_version, api_version, registered_at, health_status
             FROM workers
             WHERE manifest_hash_b3 = ?
               AND tenant_id = ?
               AND status = 'healthy'
               AND (health_status IS NULL OR health_status IN ('healthy', 'unknown'))
             ORDER BY avg_latency_ms ASC NULLS LAST",
        )
        .bind(manifest_hash)
        .bind(tenant_id)
        .fetch_all(self.pool())
        .await
        .map_err(|e| {
            AosError::Database(format!(
                "Failed to list compatible workers for tenant: {}",
                e
            ))
        })?;

let initial_count = workers.len();

// Filter by schema version compatibility (major.minor must match)
        // This is defense-in-depth; incompatible workers shouldn't be registered
        let compatible_workers: Vec<WorkerWithBinding> = workers
            .into_iter()
            .filter(|w| match w.schema_version.as_deref() {
                Some(sv) if is_schema_compatible(sv, API_SCHEMA_VERSION) => true,
                Some(sv) => {
                    debug!(
                        worker_id = %w.id,
                        worker_schema = %sv,
                        cp_schema = %API_SCHEMA_VERSION,
                        tenant_id = %tenant_id,
                        "Worker excluded: schema version incompatible"
                    );
                    false
                }
                None => {
                    warn!(
                        worker_id = %w.id,
                        tenant_id = %tenant_id,
                        "Worker excluded: schema_version is NULL (worker may need re-registration)"
                    );
                    false
                }
            })
            .collect();

if compatible_workers.len() < initial_count {
            debug!(
                manifest_hash = %manifest_hash,
                tenant_id = %tenant_id,
                initial_count = initial_count,
                compatible_count = compatible_workers.len(),
                filtered_out = initial_count - compatible_workers.len(),
                "Some workers filtered out due to schema incompatibility"
            );
        }

Ok(compatible_workers)
    }

/// List healthy workers
    ///
    /// Returns all workers with:
    /// - status = 'healthy'
    /// - schema_version compatible with control plane (major.minor match)
    /// - healthy status
    ///
    /// Used for routing when manifest matching is not required.
    pub async fn list_healthy_workers(&self) -> Result<Vec<WorkerWithBinding>> {
        use adapteros_core::version::API_SCHEMA_VERSION;

let workers = sqlx::query_as::<_, WorkerWithBinding>(
            "SELECT id, tenant_id, node_id, plan_id, uds_path, pid, status,
                    started_at, last_seen_at, manifest_hash_b3, backend, model_hash_b3,
                    capabilities_json, schema_version, api_version, registered_at, health_status
             FROM workers
             WHERE status = 'healthy'
               AND (health_status IS NULL OR health_status IN ('healthy', 'unknown'))
             ORDER BY avg_latency_ms ASC NULLS LAST",
        )
        .fetch_all(self.pool())
        .await
        .map_err(|e| AosError::Database(format!("Failed to list serving workers: {}", e)))?;

let initial_count = workers.len();

let result = list_training_jobs(
        State(state),
        Extension(claims),
        Query(TrainingListParams::default()),
    )
    .await;

assert!(result.is_ok(), "list should succeed even when empty");
    let jobs = result.unwrap().0;
    // Should return valid response (may be empty or have test data)
    assert!(jobs.jobs.is_empty() || !jobs.jobs.is_empty());

Ok(())
}

//! Policy pack signing and verification
//!
//! Implements Ed25519 signing and verification for policy packs to ensure
//! integrity and authenticity of policy configurations.

use adapteros_core::{AosError, Result};
use adapteros_crypto::signature::{Keypair, PublicKey, Signature};
use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;

/// Policy pack with signature metadata
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SignedPolicyPack {
    pub policy_id: String,
    pub version: String,
    pub policy_data: BTreeMap<String, serde_json::Value>,
    pub signature: String,
    pub public_key: String,
    pub schema_version: u8,
}

impl SignedPolicyPack {
    /// Sign a policy pack with Ed25519
    pub fn sign(
        policy_id: &str,
        version: &str,
        policy_data: BTreeMap<String, serde_json::Value>,
        signing_key: &Keypair,
    ) -> Result<Self> {
        let policy_bytes = serde_json::to_vec(&policy_data).map_err(AosError::Serialization)?;

let signature = signing_key.sign(&policy_bytes);
        let public_key = signing_key.public_key();

Ok(Self {
            policy_id: policy_id.to_string(),
            version: version.to_string(),
            policy_data,
            signature: hex::encode(signature.to_bytes()),
            public_key: hex::encode(public_key.to_bytes()),
            schema_version: 1,
        })
    }

/// Verify policy pack signature
    pub fn verify_signature(&self, trusted_pubkey: &PublicKey) -> Result<()> {
        // Verify signature against canonical JSON
        let policy_bytes =
            serde_json::to_vec(&self.policy_data).map_err(AosError::Serialization)?;

let sig_bytes = hex::decode(&self.signature)
            .map_err(|e| AosError::Crypto(format!("Invalid signature hex: {}", e)))?;

if sig_bytes.len() != 64 {
            return Err(AosError::Crypto(format!(
                "Invalid signature length: {}",
                sig_bytes.len()
            )));
        }

let mut sig_array = [0u8; 64];
        sig_array.copy_from_slice(&sig_bytes);
        let signature = Signature::from_bytes(&sig_array)
            .map_err(|e| AosError::Crypto(format!("Invalid signature format: {}", e)))?;

trusted_pubkey
            .verify(&policy_bytes, &signature)
            .map_err(|e| {
                AosError::Crypto(format!("Policy pack signature verification failed: {}", e))
            })?;

Ok(())
    }

/// Verify schema version compatibility
    pub fn verify_schema_version(&self) -> Result<()> {
        if self.schema_version != 1 {
            return Err(AosError::Crypto(format!(
                "Unsupported policy pack schema version: {}",
                self.schema_version
            )));
        }
        Ok(())
    }
}

/// Policy pack registry with signature verification
pub struct PolicyPackRegistry {
    trusted_keys: Vec<PublicKey>,
    signed_packs: BTreeMap<String, SignedPolicyPack>,
}

impl Default for PolicyPackRegistry {
    fn default() -> Self {
        Self::new()
    }
}

impl PolicyPackRegistry {
    /// Create a new policy pack registry
    pub fn new() -> Self {
        Self {
            trusted_keys: Vec::new(),
            signed_packs: BTreeMap::new(),
        }
    }

/// Add a trusted public key for verification
    pub fn add_trusted_key(&mut self, pubkey: PublicKey) {
        self.trusted_keys.push(pubkey);
    }

/// Register a signed policy pack
    pub fn register_pack(&mut self, pack: SignedPolicyPack) -> Result<()> {
        // Verify schema version
        pack.verify_schema_version()?;

// Validate that trusted keys are configured
        if self.trusted_keys.is_empty() {
            return Err(AosError::Crypto(
                "No trusted keys configured - cannot verify policy pack signature".to_string(),
            ));
        }

// Verify signature against trusted keys
        let mut verified = false;
        for trusted_key in &self.trusted_keys {
            if pack.verify_signature(trusted_key).is_ok() {
                verified = true;
                break;
            }
        }

if !verified {
            return Err(AosError::Crypto(
                "Policy pack signature verification failed against all trusted keys".to_string(),
            ));
        }

self.signed_packs.insert(pack.policy_id.clone(), pack);
        Ok(())
    }

//! Per-tenant KV cache quota enforcement
//!
//! Provides reservation-based quota tracking for KV cache allocations.
//! Quotas are enforced at insertion time to prevent cache starvation.

use adapteros_core::{AosError, Result};
use parking_lot::{Mutex, RwLock};
use std::sync::atomic::{AtomicU32, AtomicU64, Ordering};
use std::time::{Duration, Instant, SystemTime};
use tracing::{debug, warn};

/// Reservation timeout: 5 minutes
const RESERVATION_TIMEOUT: Duration = Duration::from_secs(300);

/// Frequency threshold for HOT promotion (number of accesses)
pub const HOT_PROMOTION_THRESHOLD: u32 = 3;

/// Recency window for HOT classification
pub const HOT_RECENCY_WINDOW: Duration = Duration::from_secs(60);

/// Space reservation for KV cache allocation
#[derive(Debug, Clone)]
pub struct KvReservation {
    /// Unique reservation ID
    pub id: String,
    /// Reserved size in bytes
    pub size_bytes: u64,
    /// Timestamp when reservation was created
    pub created_at: Instant,
    /// Timestamp when reservation expires
    pub expires_at: Instant,
}

impl KvReservation {
    /// Create new reservation
    pub fn new(id: String, size_bytes: u64) -> Self {
        let now = Instant::now();
        Self {
            id,
            size_bytes,
            created_at: now,
            expires_at: now + RESERVATION_TIMEOUT,
        }
    }

/// Check if reservation has expired
    pub fn is_expired(&self) -> bool {
        Instant::now() > self.expires_at
    }
}

/// KV quota usage statistics
#[derive(Debug, Clone)]
pub struct KvQuotaUsage {
    pub tenant_id: String,
    pub used_bytes: u64,
    pub reserved_bytes: u64,
    pub quota_bytes: Option<u64>,
    pub available_bytes: u64,
    pub usage_pct: f64,
}

/// Per-tenant KV cache quota manager
///
/// Tracks bytes used and reserved, enforcing quota at reservation time.
/// Workers are single-tenant, so one manager per worker.
pub struct TenantKvQuotaManager {
    tenant_id: String,
    /// Quota in bytes (None = unlimited)
    quota_bytes: Option<u64>,
    /// Currently used bytes (finalized allocations)
    used_bytes: AtomicU64,
    /// Currently reserved bytes (pending allocations)
    reserved_bytes: AtomicU64,
    /// Active reservations
    reservations: RwLock<Vec<KvReservation>>,
    /// Serializes quota state updates for consistent snapshots
    quota_lock: Mutex<()>,
    /// Eviction counter for current session
    evictions: AtomicU32,
    /// Whether quota enforcement is active
    quota_enforced: bool,
}

impl TenantKvQuotaManager {
    /// Create new quota manager
    ///
    /// # Arguments
    /// * `tenant_id` - Tenant identifier
    /// * `quota_bytes` - Maximum KV cache bytes (None = unlimited)
    pub fn new(tenant_id: String, quota_bytes: Option<u64>) -> Self {
        let quota_enforced = quota_bytes.is_some();
        Self {
            tenant_id,
            quota_bytes,
            used_bytes: AtomicU64::new(0),
            reserved_bytes: AtomicU64::new(0),
            reservations: RwLock::new(Vec::new()),
            quota_lock: Mutex::new(()),
            evictions: AtomicU32::new(0),
            quota_enforced,
        }
    }

/// Get tenant ID
    pub fn tenant_id(&self) -> &str {
        &self.tenant_id
    }

/// Get configured quota (None = unlimited)
    pub fn quota_bytes(&self) -> Option<u64> {
        self.quota_bytes
    }

/// Check if quota enforcement is active
    pub fn is_quota_enforced(&self) -> bool {
        self.quota_enforced
    }

/// Check if current database schema version matches expected
    ///
    /// # Arguments
    ///
    /// * `actual_version` - The database's current schema version from `_sqlx_migrations`
    ///
    /// # Returns
    ///
    /// * `Ok(())` if versions match
    /// * `Err(String)` with diagnostic message if mismatch detected
    pub fn verify_database_version(&self, actual_version: u32) -> Result<(), String> {
        if actual_version == self.database_schema {
            Ok(())
        } else if actual_version < self.database_schema {
            Err(format!(
                "Database schema is BEHIND: database at v{}, expected v{}. \
                 Missing {} migrations. Run: aosctl db migrate",
                actual_version,
                self.database_schema,
                self.database_schema - actual_version
            ))
        } else {
            Err(format!(
                "Database schema is AHEAD: database at v{}, expected v{}. \
                 Code rollback or migration file removal detected. \
                 This binary cannot safely operate with this database schema.",
                actual_version, self.database_schema
            ))
        }
    }
}

impl fmt::Display for VersionInfo {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        writeln!(f, "adapterOS {}", self.release)?;
        writeln!(f, "API Schema:      v{}", self.api_schema)?;
        writeln!(f, "Database Schema: v{}", self.database_schema)?;
        writeln!(f, "RNG Module:      v{}", self.rng_module)?;
        writeln!(f, "Git Commit:      {}", self.git_commit)?;
        writeln!(f, "Build Time:      {}", self.build_timestamp)?;
        writeln!(f, "Build Profile:   {}", self.build_profile)?;
        writeln!(
            f,
            "Target:          {}-{}",
            self.target_os, self.target_arch
        )?;
        Ok(())
    }
}

