impl Db {
    /// Migrate the selected domains from SQL to KV with deterministic ordering and tenant isolation.
    ///
    /// - Honors `tenant_filter` for tenant-scoped domains.
    /// - Respects `dry_run` (no writes).
    /// - Uses checkpoints to resume by skipping already-processed rows.
    pub async fn migrate_domains(
        &self,
        domains: &[MigrationDomain],
        opts: &MigrationOptions,
    ) -> Result<(Vec<(MigrationDomain, DomainStats)>, MigrationCheckpoint)> {
        if !self.has_kv_backend() {
            return Err(AosError::Config(
                "KV backend not attached; initialize before migration".to_string(),
            ));
        }

let mut results = Vec::new();
        let mut checkpoint = opts.checkpoint.clone().unwrap_or_default();
        let tenant_filter = opts.tenant_filter.as_deref();

for domain in domains {
            let key = domain.checkpoint_key(tenant_filter);
            let start_at = checkpoint.processed.get(&key).copied().unwrap_or(0);

let mut stats = DomainStats::default();
            let processed = self
                .migrate_domain_internal(*domain, start_at, opts, &mut stats)
                .await?;

checkpoint.processed.insert(key, start_at + processed);
            results.push((*domain, stats));
        }

Ok((results, checkpoint))
    }

async fn migrate_domain_internal(
        &self,
        domain: MigrationDomain,
        start_at: usize,
        opts: &MigrationOptions,
        stats: &mut DomainStats,
    ) -> Result<usize> {
        match domain {
            MigrationDomain::Adapters => self.migrate_domain_adapters(start_at, opts, stats).await,
            MigrationDomain::Tenants => self.migrate_domain_tenants(start_at, opts, stats).await,
            MigrationDomain::Stacks => self.migrate_domain_stacks(start_at, opts, stats).await,
            MigrationDomain::Plans => self.migrate_domain_plans(start_at, opts, stats).await,
            MigrationDomain::AuthSessions => {
                self.migrate_domain_auth_sessions(start_at, opts, stats)
                    .await
            }
            MigrationDomain::RuntimeSessions => {
                self.migrate_domain_runtime_sessions(start_at, opts, stats)
                    .await
            }
            MigrationDomain::RagArtifacts => {
                self.migrate_domain_rag_artifacts(start_at, opts, stats)
                    .await
            }
            MigrationDomain::PolicyAudit => {
                let res = self.migrate_policy_audit_to_kv().await?;
                stats.total += res.total;
                stats.migrated += res.migrated;
                stats.skipped += res.skipped;
                stats.failed += res.failed;
                stats.errors.extend(
                    res.failed_ids
                        .into_iter()
                        .map(|id| format!("policy_audit:{id}")),
                );
                Ok(res.total)
            }
            MigrationDomain::TrainingJobs => {
                let res = self.migrate_training_jobs_to_kv().await?;
                stats.total += res.total;
                stats.migrated += res.migrated;
                stats.skipped += res.skipped;
                stats.failed += res.failed;
                stats.errors.extend(
                    res.failed_ids
                        .into_iter()
                        .map(|id| format!("training_job:{id}")),
                );
                Ok(res.total)
            }
            MigrationDomain::ChatSessions => {
                let res = self.migrate_chat_sessions_to_kv().await?;
                stats.total += res.total;
                stats.migrated += res.migrated;
                stats.skipped += res.skipped;
                stats.failed += res.failed;
                stats.errors.extend(
                    res.failed_ids
                        .into_iter()
                        .map(|id| format!("chat_session:{id}")),
                );
                Ok(res.total)
            }
        }
    }

async fn migrate_domain_adapters(
        &self,
        start_at: usize,
        opts: &MigrationOptions,
        stats: &mut DomainStats,
    ) -> Result<usize> {
        let kv_backend = self.kv_backend().ok_or_else(|| {
            AosError::Config("KV backend not initialized; cannot migrate adapters".to_string())
        })?;

let adapters = if let Some(tid) = opts.tenant_filter.as_deref() {
            self.list_adapters_for_tenant(tid).await?
        } else {
            #[allow(deprecated)]
            self.list_all_adapters_system().await?
        };

let mut adapters = adapters;
        adapters.sort_by(|a, b| {
            b.created_at
                .cmp(&a.created_at)
                .then_with(|| a.id.cmp(&b.id))
        });

let mut processed = 0usize;
        for (idx, adapter) in adapters.into_iter().enumerate() {
            if idx < start_at {
                continue;
            }
            processed += 1;
            stats.total += 1;

if opts.dry_run {
                stats.skipped += 1;
                continue;
            }

Ok(())
}

/// Checks schema version compatibility between application and database.
///
/// This function compares the application's expected schema version with
/// the database's current version to determine what action (if any) is needed.
///
/// # Arguments
///
/// * `app_version` - The schema version the application expects
/// * `db_version` - The schema version currently in the database
///
/// # Returns
///
/// * `Ok(VersionCheck::Compatible)` if versions match
/// * `Ok(VersionCheck::NeedsMigration { from, to })` if database needs updating
/// * `Ok(VersionCheck::DatabaseAhead { ... })` if database is ahead of application
/// * `Err(AosStorageError::SchemaVersionMismatch)` if the mismatch is critical
///
/// # Example
///
/// ```ignore
/// match check_schema_version(5, 3)? {
///     VersionCheck::Compatible => {},
///     VersionCheck::NeedsMigration { from, to } => {
///         run_migrations(from, to)?;
///     },
///     VersionCheck::DatabaseAhead { .. } => {
///         // Handle downgrade scenario
///     }
/// }
/// ```
pub fn check_schema_version(
    app_version: i64,
    db_version: i64,
) -> Result<VersionCheck, AosStorageError> {
    match app_version.cmp(&db_version) {
        std::cmp::Ordering::Equal => Ok(VersionCheck::Compatible),
        std::cmp::Ordering::Greater => {
            // Database is behind - needs migration
            Ok(VersionCheck::NeedsMigration {
                from: db_version,
                to: app_version,
            })
        }
        std::cmp::Ordering::Less => {
            // Database is ahead - possible downgrade scenario
            // This is typically an error condition
            Ok(VersionCheck::DatabaseAhead {
                app_version,
                db_version,
            })
        }
    }
}

/// Checks schema version compatibility and returns an error for critical mismatches.
///
/// Unlike `check_schema_version`, this function returns an error if the database
/// is ahead of the application version, as this typically indicates a deployment
/// issue where an older application is connecting to a newer database.
///
/// # Arguments
///
/// * `app_version` - The schema version the application expects
/// * `db_version` - The schema version currently in the database
///
/// # Returns
///
/// * `Ok(VersionCheck)` for compatible scenarios
/// * `Err(AosStorageError::SchemaVersionMismatch)` if database is ahead
pub fn check_schema_version_strict(
    app_version: i64,
    db_version: i64,
) -> Result<VersionCheck, AosStorageError> {
    let check = check_schema_version(app_version, db_version)?;

if let VersionCheck::DatabaseAhead {
        app_version,
        db_version,
    } = check
    {
        return Err(AosStorageError::SchemaVersionMismatch {
            app_version,
            db_version,
            direction: "ahead".to_string(),
        });
    }

Ok(check)
}

