use crate::auth::{AuthMode, Claims, PrincipalType};
use crate::state::AppState;
use adapteros_api_types::{RunActor, RunEnvelope, API_SCHEMA_VERSION};
use adapteros_db::workers::WorkerWithBinding;
use chrono::Utc;
use tracing::warn;

pub const RUN_ENVELOPE_VERSION: &str = "v1";

/// Build a canonical run envelope at the API edge.
pub fn new_run_envelope(
    state: &AppState,
    claims: &Claims,
    run_id: String,
    reasoning_mode: bool,
) -> RunEnvelope {
    let mut roles = claims.roles.clone();
    roles.push(claims.role.clone());
    roles.sort();
    roles.dedup();

let subject = match claims.auth_mode {
        AuthMode::DevBypass => "dev-bypass".to_string(),
        AuthMode::Unauthenticated => "anonymous".to_string(),
        _ => claims.sub.clone(),
    };

let actor = RunActor {
        subject,
        roles,
        principal_type: claims
            .principal_type
            .as_ref()
            .map(principal_type_to_str)
            .map(ToOwned::to_owned),
        auth_mode: Some(auth_mode_to_str(&claims.auth_mode)),
    };

let manifest_hash_b3 = state.manifest_hash.clone();
    if manifest_hash_b3.is_none() {
        warn!(
            run_id = %run_id,
            "Manifest hash not set on AppState; run envelope will be degraded"
        );
    }

let tick = state
        .tick_ledger
        .as_ref()
        .map(|ledger| ledger.increment_tick());

RunEnvelope {
        run_id,
        schema_version: API_SCHEMA_VERSION.to_string(),
        workspace_id: claims.tenant_id.clone(),
        actor,
        manifest_hash_b3,
        plan_id: None,
        policy_mask_digest_b3: None,
        router_seed: None,
        tick,
        worker_id: None,
        reasoning_mode,
        determinism_version: RUN_ENVELOPE_VERSION.to_string(),
        boot_trace_id: state.boot_state.as_ref().map(|boot| boot.boot_trace_id()),
        created_at: Utc::now(),
    }
}

/// Record policy mask digest onto the envelope.
pub fn set_policy_mask(envelope: &mut RunEnvelope, digest: Option<&[u8; 32]>) {
    envelope.policy_mask_digest_b3 = digest.map(hex::encode);
}

/// Attach router seed to the envelope.
pub fn set_router_seed(envelope: &mut RunEnvelope, seed: Option<&String>) {
    if let Some(seed) = seed {
        envelope.router_seed = Some(seed.clone());
    }
}

/// Attach worker and plan context once selection is known.
pub fn set_worker_context(
    envelope: &mut RunEnvelope,
    worker: Option<&WorkerWithBinding>,
    manifest_hash: Option<String>,
) {
    if let Some(worker) = worker {
        envelope.worker_id = Some(worker.id.clone());
        envelope.plan_id = Some(worker.plan_id.clone());
        if envelope.manifest_hash_b3.is_none() {
            envelope.manifest_hash_b3 = worker.manifest_hash_b3.clone();
        }
    }

if let Some(manifest_hash) = manifest_hash {
        envelope.manifest_hash_b3 = Some(manifest_hash);
    }
}

fn auth_mode_to_str(mode: &AuthMode) -> String {
    match mode {
        AuthMode::BearerToken => "bearer".to_string(),
        AuthMode::Cookie => "cookie".to_string(),
        AuthMode::ApiKey => "api_key".to_string(),
        AuthMode::DevBypass => "dev_bypass".to_string(),
        AuthMode::Unauthenticated => "unauthenticated".to_string(),
    }
}

fn principal_type_to_str(principal: &PrincipalType) -> &'static str {
    match principal {
        PrincipalType::User => "user",
        PrincipalType::ApiKey => "api_key",
        PrincipalType::DevBypass => "dev_bypass",
        PrincipalType::InternalService => "internal_service",
    }
}

#[test]
    fn test_checksum_very_long_content() {
        // 1MB of content
        let content = "CREATE TABLE test;".repeat(50000);
        let hash = compute_hash(&content);
        assert!(verify_migration_checksum("V001__large.sql", &content, &hash).is_ok());
    }

#[test]
    fn test_checksum_single_character_difference() {
        let content1 = "CREATE TABLE users (id INT);";
        let content2 = "CREATE TABLE users (id INt);"; // lowercase 't'
        let hash1 = compute_hash(content1);

// Verify original works
        assert!(verify_migration_checksum("V001__test.sql", content1, &hash1).is_ok());

// Single character difference should fail
        let result = verify_migration_checksum("V001__test.sql", content2, &hash1);
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));
    }

#[test]
    fn test_checksum_trailing_newline_difference() {
        let content_with_newline = "CREATE TABLE users (id INT);\n";
        let content_without_newline = "CREATE TABLE users (id INT);";

let hash_with = compute_hash(content_with_newline);
        let hash_without = compute_hash(content_without_newline);

// Hashes should be different
        assert_ne!(hash_with, hash_without);

// Cross-verification should fail
        let result =
            verify_migration_checksum("V001__test.sql", content_without_newline, &hash_with);
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));
    }

#[test]
    fn test_checksum_crlf_vs_lf() {
        let content_lf = "CREATE TABLE users;\nINSERT INTO users;";
        let content_crlf = "CREATE TABLE users;\r\nINSERT INTO users;";

let hash_lf = compute_hash(content_lf);

// CRLF content with LF hash should fail
        let result = verify_migration_checksum("V001__test.sql", content_crlf, &hash_lf);
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));
    }

#[test]
    fn test_checksum_invalid_hex_hash() {
        let content = "CREATE TABLE users;";

// Invalid hex (not enough characters)
        let result = verify_migration_checksum("V001__test.sql", content, "abc");
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));

// Invalid hex (wrong characters)
        let result = verify_migration_checksum("V001__test.sql", content, &"gg".repeat(32));
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));
    }

#[test]
    fn test_checksum_case_sensitivity() {
        let content = "CREATE TABLE users;";
        let hash_lower = compute_hash(content);
        let hash_upper = hash_lower.to_uppercase();

// Lowercase hash should work
        assert!(verify_migration_checksum("V001__test.sql", content, &hash_lower).is_ok());

// Uppercase hash should NOT work (hex comparison is case-sensitive)
        let result = verify_migration_checksum("V001__test.sql", content, &hash_upper);
        assert!(matches!(
            result,
            Err(AosStorageError::MigrationChecksumMismatch { .. })
        ));
    }

#[test]
    fn test_checksum_error_contains_filename() {
        let content = "CREATE TABLE test;";
        let wrong_hash = "0".repeat(64);

match verify_migration_checksum("V999__special_file.sql", content, &wrong_hash) {
            Err(AosStorageError::MigrationChecksumMismatch {
                filename,
                expected,
                actual,
            }) => {
                assert_eq!(filename, "V999__special_file.sql");
                assert_eq!(expected, wrong_hash);
                assert_eq!(actual, compute_hash(content));
            }
            _ => panic!("Expected MigrationChecksumMismatch error"),
        }
    }

