//! Unix Domain Socket metrics exporter
//!
//! Provides Prometheus-compatible metrics export via Unix domain sockets,
//! ensuring zero network egress during serving (Egress Ruleset #1).

use adapteros_core::{AosError, Result};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::PathBuf;
use std::sync::Arc;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::net::{UnixListener, UnixStream};
use tokio::sync::{broadcast, Mutex};
use tracing::{debug, error, info, warn};

/// Metric value types
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum MetricValue {
    /// Counter (monotonically increasing)
    Counter(f64),
    /// Gauge (can go up or down)
    Gauge(f64),
    /// Histogram bucket
    Histogram {
        count: u64,
        sum: f64,
        buckets: Vec<(f64, u64)>,
    },
    /// Summary
    Summary {
        count: u64,
        sum: f64,
        quantiles: Vec<(f64, f64)>,
    },
}

/// Metric metadata
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MetricMetadata {
    /// Metric name
    pub name: String,
    /// Help text
    pub help: String,
    /// Metric type
    pub metric_type: String,
    /// Labels
    pub labels: HashMap<String, String>,
    /// Value
    pub value: MetricValue,
}

/// Unix Domain Socket metrics exporter
pub struct UdsMetricsExporter {
    /// Socket path
    socket_path: PathBuf,
    /// Listener
    listener: Option<UnixListener>,
    /// Metrics registry
    metrics_registry: Arc<Mutex<HashMap<String, MetricMetadata>>>,
    /// Whether to enable Prometheus compatibility
    prometheus_compat: bool,
}

impl UdsMetricsExporter {
    /// Create a new UDS metrics exporter
    pub fn new(socket_path: PathBuf) -> Result<Self> {
        Ok(Self {
            socket_path,
            listener: None,
            metrics_registry: Arc::new(Mutex::new(HashMap::new())),
            prometheus_compat: true,
        })
    }

/// Create with Prometheus compatibility disabled
    pub fn with_prometheus_compat(mut self, enabled: bool) -> Self {
        self.prometheus_compat = enabled;
        self
    }

/// Gracefully shutdown the UDS metrics exporter
    ///
    /// Closes the listener socket and cleans up resources.
    /// Existing connections will complete naturally.
    pub async fn shutdown(&mut self) -> Result<()> {
        info!("Shutting down UDS metrics exporter");

if let Some(listener) = self.listener.take() {
            // Drop the listener to stop accepting new connections
            drop(listener);
        }

// Clean up the socket file
        if self.socket_path.exists() {
            if let Err(e) = std::fs::remove_file(&self.socket_path) {
                warn!("Failed to remove UDS socket file during shutdown: {}", e);
            } else {
                info!("UDS socket file cleaned up");
            }
        }

info!("UDS metrics exporter shutdown complete");
        Ok(())
    }

/// Bind to the Unix domain socket
    pub async fn bind(&mut self) -> Result<()> {
        // Remove existing socket if present
        if self.socket_path.exists() {
            std::fs::remove_file(&self.socket_path).map_err(|e| {
                AosError::Telemetry(format!("Failed to remove existing socket: {}", e))
            })?;
        }

// Create parent directory if needed
        if let Some(parent) = self.socket_path.parent() {
            std::fs::create_dir_all(parent).map_err(|e| {
                AosError::Telemetry(format!("Failed to create socket directory: {}", e))
            })?;
        }

// Bind listener
        let listener = UnixListener::bind(&self.socket_path)
            .map_err(|e| AosError::Telemetry(format!("Failed to bind UDS listener: {}", e)))?;

/// Verify policy signature using server's public key (PRD-SEC-01)
pub async fn verify_policy_signature(
    State(state): State<AppState>,
    Extension(claims): Extension<Claims>,
    Path(cpid): Path<String>,
) -> Result<Json<VerifyPolicyResponse>, (StatusCode, Json<ErrorResponse>)> {
    // Role check: Any authenticated user can verify signatures
    crate::permissions::require_permission(&claims, crate::permissions::Permission::PolicyView)?;

// Fetch the policy pack to get its signature
    let policy_pack = state
        .db
        .get_policy_pack(&cpid)
        .await
        .map_err(|e| {
            tracing::error!(cpid = %cpid, error = %e, "Failed to get policy pack");
            (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(
                    ErrorResponse::new("Failed to get policy pack")
                        .with_code("INTERNAL_ERROR")
                        .with_string_details(e.to_string()),
                ),
            )
        })?
        .ok_or_else(|| {
            (
                StatusCode::NOT_FOUND,
                Json(ErrorResponse::new("Policy pack not found").with_code("NOT_FOUND")),
            )
        })?;

// Get the signature from the policy pack (if exists)
    let signature_str = policy_pack.signature.clone();

// Extract the signature bytes (strip "ed25519:" prefix if present)
    let signature_hex = if let Some(stripped) = signature_str.strip_prefix("ed25519:") {
        stripped
    } else {
        &signature_str
    };

// Parse the signature
    let signature_bytes = hex::decode(signature_hex).map_err(|e| {
        tracing::error!("Invalid signature hex: {}", e);
        (
            StatusCode::BAD_REQUEST,
            Json(
                ErrorResponse::new("Invalid signature format")
                    .with_code("INVALID_SIGNATURE")
                    .with_string_details(e.to_string()),
            ),
        )
    })?;

if signature_bytes.len() != 64 {
        return Err((
            StatusCode::BAD_REQUEST,
            Json(
                ErrorResponse::new("Invalid signature length")
                    .with_code("INVALID_SIGNATURE")
                    .with_string_details(format!(
                        "Expected 64 bytes, got {}",
                        signature_bytes.len()
                    )),
            ),
        ));
    }

let mut sig_array = [0u8; 64];
    sig_array.copy_from_slice(&signature_bytes);

// Get the server's public key
    use adapteros_crypto::signature::Signature;
    let public_key = state.ed25519_keypair.public_key();
    let public_key_hex = hex::encode(public_key.to_bytes());

// Verify the signature
    let signature = Signature::from_bytes(&sig_array).map_err(|e| {
        tracing::error!("Failed to parse signature: {}", e);
        (
            StatusCode::BAD_REQUEST,
            Json(
                ErrorResponse::new("Failed to parse signature")
                    .with_code("INVALID_SIGNATURE")
                    .with_string_details(e.to_string()),
            ),
        )
    })?;

let is_valid = match public_key.verify(cpid.as_bytes(), &signature) {
        Ok(()) => {
            tracing::info!(
                cpid = %cpid,
                verified_by = %claims.email,
                "Policy signature verified successfully"
            );
            true
        }
        Err(e) => {
            tracing::warn!(
                cpid = %cpid,
                verified_by = %claims.email,
                error = %e,
                "Policy signature verification failed"
            );
            false
        }
    };

Ok(Json(VerifyPolicyResponse {
        cpid: cpid.clone(),
        signature: signature_str,
        is_valid,
        public_key: format!("ed25519:{}", public_key_hex),
        verified_at: chrono::Utc::now().to_rfc3339(),
        error: if is_valid {
            None
        } else {
            Some("Signature verification failed".to_string())
        },
    }))
}

/// Compare two policy versions
pub async fn compare_policy_versions(
    State(state): State<AppState>,
    Extension(_claims): Extension<Claims>,
    Json(req): Json<PolicyComparisonRequest>,
) -> Result<Json<PolicyComparisonResponse>, (StatusCode, Json<ErrorResponse>)> {
    // Fetch both policy packs
    let pack1 = state
        .db
        .get_policy_pack(&req.cpid_1)
        .await
        .map_err(|e| {
            tracing::error!(cpid = %req.cpid_1, error = %e, "Failed to get policy pack");
            (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(
                    ErrorResponse::new("Failed to get policy pack")
                        .with_code("INTERNAL_ERROR")
                        .with_string_details(e.to_string()),
                ),
            )
        })?
        .ok_or_else(|| {
            (
                StatusCode::NOT_FOUND,
                Json(ErrorResponse::new("Policy pack 1 not found").with_code("NOT_FOUND")),
            )
        })?;

// Hash all plan files in the directory
    let mut hasher = blake3::Hasher::new();

if plan_path.is_dir() {
        let mut entries: Vec<_> = std::fs::read_dir(plan_path)
            .map(|rd| rd.filter_map(|e| e.ok()).collect())
            .unwrap_or_default();

// Sort for deterministic ordering
        entries.sort_by_key(|e| e.path());

for entry in entries {
            let path = entry.path();
            if path.is_file()
                && (path
                    .extension()
                    .map(|e| e == "json" || e == "yaml")
                    .unwrap_or(false))
            {
                if let Ok(contents) = std::fs::read(&path) {
                    hasher.update(path.file_name().unwrap_or_default().as_encoded_bytes());
                    hasher.update(&contents);
                }
            }
        }
    } else if plan_path.is_file() {
        if let Ok(contents) = std::fs::read(plan_path) {
            hasher.update(&contents);
        }
    }

B3Hash::new(*hasher.finalize().as_bytes())
}

/// Compute hash of the kernel library
fn compute_kernel_hash(kernel_path: &std::path::Path) -> B3Hash {
    if !kernel_path.exists() {
        warn!(path = %kernel_path.display(), "Kernel path does not exist, using zero hash");
        return B3Hash::zero();
    }

// Hash kernel library files (.metallib, .mlmodelc, etc.)
    let mut hasher = blake3::Hasher::new();

if kernel_path.is_dir() {
        let mut entries: Vec<_> = std::fs::read_dir(kernel_path)
            .map(|rd| rd.filter_map(|e| e.ok()).collect())
            .unwrap_or_default();

entries.sort_by_key(|e| e.path());

for entry in entries {
            let path = entry.path();
            if path.is_file() {
                let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("");
                if matches!(ext, "metallib" | "mlmodelc" | "dylib" | "so" | "a") {
                    if let Ok(contents) = std::fs::read(&path) {
                        hasher.update(path.file_name().unwrap_or_default().as_encoded_bytes());
                        hasher.update(&contents);
                    }
                }
            }
        }
    } else if kernel_path.is_file() {
        if let Ok(contents) = std::fs::read(kernel_path) {
            hasher.update(&contents);
        }
    }

B3Hash::new(*hasher.finalize().as_bytes())
}

/// Sign manifest data with node's Ed25519 key
fn sign_manifest(data: &[u8]) -> Result<String> {
    // Load or generate node signing key
    let key_path = std::path::Path::new("/var/lib/aos/node.key");

let signing_key = if key_path.exists() {
        // Load existing key
        let key_bytes = std::fs::read(key_path)?;
        let key_array: [u8; 32] = key_bytes
            .try_into()
            .map_err(|_| anyhow::anyhow!("Invalid key length"))?;
        SigningKey::from_bytes(&key_array)
    } else {
        // Generate new key for this node
        let mut csprng = rand::rngs::OsRng;
        let key = SigningKey::generate(&mut csprng);
        if let Some(parent) = key_path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(key_path, key.to_bytes())?;
        key
    };

let signature = signing_key.sign(data);
    Ok(hex::encode(signature.to_bytes()))
}

