/// Emit an event to all subscribed plugins
    ///
    /// Features:
    /// - Timeout enforcement (5 seconds per plugin handler)
    /// - Panic isolation (plugin crashes don't affect the server)
    /// - Error logging (failures are logged but don't stop event dispatch)
    /// - Non-blocking (uses broadcast channel)
    ///
    /// Returns a list of plugin names that failed to handle the event.
    ///
    /// # Arguments
    ///
    /// * `event` - Event to dispatch to plugins
    ///
    /// # Returns
    ///
    /// * `Ok(())` - Event dispatched successfully (failures are logged but not returned as errors)
    /// * `Err(failures)` - List of plugin names that failed to handle the event
    ///
    /// # Example
    ///
    /// ```no_run
    /// # use adapteros_server_api::event_bus::EventBus;
    /// # use adapteros_core::{PluginEvent, AdapterEvent};
    /// # use std::collections::HashMap;
    /// # async fn example(event_bus: &EventBus) -> Result<(), Vec<String>> {
    /// let event = PluginEvent::AdapterRegistered(AdapterEvent {
    ///     adapter_id: "my-adapter".to_string(),
    ///     action: "registered".to_string(),
    ///     hash: None,
    ///     tier: None,
    ///     rank: None,
    ///     tenant_id: None,
    ///     lifecycle_state: None,
    ///     timestamp: "2025-11-25T12:00:00Z".to_string(),
    ///     metadata: HashMap::new(),
    /// });
    ///
    /// event_bus.emit(event).await?;
    /// # Ok(())
    /// # }
    /// ```
    pub async fn emit(&self, event: PluginEvent) -> Result<(), Vec<String>> {
        let event_type = self.event_to_hook_type(&event);

debug!(
            event_type = ?event_type,
            event_timestamp = %event.timestamp(),
            tenant_id = ?event.tenant_id(),
            "Emitting plugin event"
        );

// Get subscribed plugins for this event type
        let plugin_names = {
            let subscriptions = self.subscriptions.read().await;
            subscriptions.get(&event_type).cloned().unwrap_or_default()
        };

if plugin_names.is_empty() {
            debug!(event_type = ?event_type, "No plugins subscribed to event type");
            return Ok(());
        }

debug!(
            event_type = ?event_type,
            subscriber_count = plugin_names.len(),
            "Dispatching event to subscribers"
        );

let mut failures = Vec::new();

// Dispatch to each subscribed plugin
        for plugin_name in plugin_names {
            let plugin = {
                let registry = self.registry.read().await;
                registry.get(&plugin_name).cloned()
            };

let Some(plugin) = plugin else {
                warn!(
                    plugin = %plugin_name,
                    event_type = ?event_type,
                    "Plugin subscribed but not found in registry"
                );
                failures.push(plugin_name);
                continue;
            };

// Clone event for this plugin handler
            let event_clone = event.clone();

// Dispatch with timeout and panic isolation
            let result = tokio::time::timeout(
                Duration::from_secs(5),
                Self::isolated_dispatch(plugin, event_clone, plugin_name.clone()),
            )
            .await;

for v in versions {
            let Some(path_str) = &v.aos_path else {
                continue;
            };
            let path = PathBuf::from(path_str);
            if !path.exists() {
                let severity = if v.release_state.eq_ignore_ascii_case("archived") {
                    "info"
                } else {
                    "error"
                };
                self.record_issue(NewStorageIssue {
                    tenant_id: Some(&v.tenant_id),
                    owner_type: "adapter_version",
                    owner_id: &v.repo_id,
                    version_id: Some(&v.id),
                    issue_type: "missing_bytes",
                    severity,
                    location: path.to_string_lossy().as_ref(),
                    details: Some("Adapter artifact missing"),
                })
                .await?;
                continue;
            }

if let Some(expected_hash) = &v.aos_hash {
                let bytes = fs::read(&path).await.map_err(|e| {
                    adapteros_core::AosError::Io(format!(
                        "Failed to read adapter artifact {}: {}",
                        path.display(),
                        e
                    ))
                })?;
                let hash = B3Hash::hash(&bytes).to_hex();
                if &hash != expected_hash {
                    self.record_issue(NewStorageIssue {
                        tenant_id: Some(&v.tenant_id),
                        owner_type: "adapter_version",
                        owner_id: &v.repo_id,
                        version_id: Some(&v.id),
                        issue_type: "hash_mismatch",
                        severity: "error",
                        location: path.to_string_lossy().as_ref(),
                        details: Some("Adapter artifact hash mismatch"),
                    })
                    .await?;
                }
            }
        }

Ok(())
    }

async fn detect_orphans(&self, _store: &FsByteStorage) -> adapteros_core::Result<()> {
        let mut expected: HashSet<PathBuf> = HashSet::new();

// Dataset version storage paths
        for v in self
            .state
            .db
            .list_all_dataset_versions()
            .await
            .unwrap_or_default()
        {
            expected.insert(canonical(&v.storage_path));
        }

// Dataset file entries
        for f in self
            .state
            .db
            .list_all_dataset_files()
            .await
            .unwrap_or_default()
        {
            expected.insert(canonical(&f.file_path));
        }

// Adapter version artifacts
        for v in self
            .state
            .db
            .list_all_adapter_versions()
            .await
            .unwrap_or_default()
        {
            if let Some(path) = &v.aos_path {
                expected.insert(canonical(path));
            }
        }

// Scan dataset root for orphans
        let dataset_root = resolve_dataset_root(&self.state)?.join("files");
        self.scan_orphans_in_dir(&dataset_root, "dataset", &expected)
            .await?;

// Scan adapter repo root for orphans
        let adapter_root = {
            let cfg = match self.state.config.read() {
                Ok(cfg) => cfg,
                Err(_) => {
                    tracing::error!("Config lock poisoned in detect_orphans");
                    return Err(adapteros_core::AosError::Internal(
                        "Config lock poisoned".to_string(),
                    ));
                }
            };
            PathBuf::from(&cfg.paths.adapters_root)
        };
        self.scan_orphans_in_dir(&adapter_root, "adapter", &expected)
            .await?;

Ok(())
    }

async fn scan_orphans_in_dir(
        &self,
        root: &Path,
        category: &str,
        expected: &HashSet<PathBuf>,
    ) -> adapteros_core::Result<()> {
        if !root.exists() {
            return Ok(());
        }

for entry in WalkDir::new(root)
            .into_iter()
            .filter_map(|e| e.ok())
            .filter(|e| e.file_type().is_file())
        {
            let p = entry.path();
            let canon = canonical(p);
            if !expected.contains(&canon) {
                self.record_issue(NewStorageIssue {
                    tenant_id: None,
                    owner_type: "orphan",
                    owner_id: category,
                    version_id: None,
                    issue_type: "orphan_bytes",
                    severity: "warn",
                    location: canon.to_string_lossy().as_ref(),
                    details: Some("File present without DB owner"),
                })
                .await?;
            }
        }

Ok(())
    }

async fn record_issue(&self, issue: NewStorageIssue<'_>) -> adapteros_core::Result<()> {
        self.state.db.record_storage_issue(issue).await?;
        Ok(())
    }
}

pub fn spawn_storage_reconciler(state: Arc<AppState>) {
    state
        .background_task_tracker()
        .record_spawned("Storage reconciler", false);
    let reconciler = StorageReconciler::new(state);
    tokio::spawn(async move {
        loop {
            reconciler.run_once().await;
            sleep(Duration::from_secs(900)).await; // 15 min cadence
        }
    });
}

fn canonical<P: AsRef<Path>>(p: P) -> PathBuf {
    match p.as_ref().canonicalize() {
        Ok(c) => c,
        Err(_) => p.as_ref().to_path_buf(),
    }
}

let stream_state = StreamState {
        db: state.db.clone(),
        tenant_id: claims.tenant_id.clone(),
        last_timestamp: initial_timestamp.clone(),
        sent_initial: false,
    };

// Use unfold to create a polling stream
    let stream = futures_util::stream::unfold(stream_state, |mut state| async move {
        // First iteration: send connection event
        if !state.sent_initial {
            state.sent_initial = true;
            let event = Event::default().event("connected").data(format!(
                r#"{{"tenant_id":"{}","connected_at":"{}"}}"#,
                state.tenant_id, state.last_timestamp
            ));
            return Some((Ok(event), state));
        }

// Wait before polling
        tokio::time::sleep(Duration::from_secs(2)).await;

// Query for new errors since last timestamp
        match state
            .db
            .list_client_errors_since(&state.tenant_id, &state.last_timestamp, Some(50))
            .await
        {
            Ok(errors) if !errors.is_empty() => {
                // Update last_timestamp to the newest error
                if let Some(newest) = errors.last() {
                    state.last_timestamp = newest.created_at.clone();
                }

// For simplicity, send the first error and re-enter the loop
                // (unfold only yields one item per iteration)
                if let Some(error) = errors.into_iter().next() {
                    let item: ClientErrorItem = error.into();
                    if let Ok(json) = serde_json::to_string(&item) {
                        let event = Event::default().event("client_error").data(json);
                        return Some((Ok(event), state));
                    }
                }
                // Fallback to heartbeat
                let event = Event::default().comment("heartbeat");
                Some((Ok(event), state))
            }
            Ok(_) => {
                // No new errors, send heartbeat
                let event = Event::default().comment("heartbeat");
                Some((Ok(event), state))
            }
            Err(e) => {
                tracing::warn!(error = %e, "Error polling for client errors");
                // Continue polling despite errors - send heartbeat
                let event = Event::default().comment("heartbeat");
                Some((Ok(event), state))
            }
        }
    });

Sse::new(stream).keep_alive(KeepAlive::default())
}

