    pub default_dir_mode: u32,
}

/// Unix-specific attributes
#[derive(Debug, Clone)]
pub struct UnixAttributes {
    /// File mode (permissions)
    pub mode: u32,
    /// User ID
    pub uid: u32,
    /// Group ID
    pub gid: u32,
