        unsafe { ffi::coreml_tensor_to_floats(product, output.as_mut_ptr(), output.len()) };
    assert!(
        read_result >= 0,
        "Failed to read matmul result: error {}",
        read_result
    );

let expected = vec![19.0f32, 22.0, 43.0, 50.0];
    assert_eq!(
        output, expected,
        "ObjC++ matmul result mismatch: expected {:?}, got {:?}",
        expected, output
    );

