// Ciphertext should be different from plaintext
    assert_ne!(ciphertext.as_slice(), plaintext);

// Decrypt
    let decrypted = decrypt_envelope(&key, &ciphertext, &nonce).unwrap();
    assert_eq!(decrypted, plaintext);
}

