    let result1 = counter1.load(Ordering::Relaxed);

// Run 2 with same seed
    let executor2 = Arc::new(create_executor(seed));
    let counter2 = Arc::new(AtomicU64::new(0));

for _i in 0..50 {
        let counter_clone = counter2.clone();
