async fn stop_service(service: ServiceKind, cli: &Cli) -> Result<()> {
    let name = service_name(&service);
    let pid_file = pid_file_for(&service)
        .ok_or_else(|| AosError::Config(format!("No PID file configured for service: {}", name)))?;

let existing_pid = read_pid(pid_file);
    if existing_pid.is_none() {
        if cli.json {
            print_json_status(&ServiceStatus {
                service: name.to_string(),
                status: "stopped".to_string(),
                pid: None,
            })?;
        } else {
            println!("{} is not running", name);
        }
        return Ok(());
    }
    let pid = existing_pid.unwrap();

if cli.dry_run {
        info!(
            component = "aos",
            service = name,
            action = "stop",
            result = "dry-run",
            pid = pid,
            "Dry-run: would stop service"
        );
        if cli.json {
            print_json_status(&ServiceStatus {
                service: name.to_string(),
                status: "would-stop".to_string(),
                pid: Some(pid),
            })?;
        } else {
            println!("Dry-run: would stop {} (pid={})", name, pid);
        }
        return Ok(());
    }

// Try graceful termination
    #[cfg(unix)]
    {
        unsafe {
            libc::kill(pid as i32, libc::SIGTERM);
        }
    }

// Best-effort: remove PID file regardless of outcome
    let _ = fs::remove_file(pid_file);

// Update status file to reflect stopped state
    update_status_file(name, "stopped", None)?;

info!(
        component = "aos",
        service = name,
        action = "stop",
        result = "requested",
        pid = pid,
        "Stop signal sent"
    );

if cli.json {
        print_json_status(&ServiceStatus {
            service: name.to_string(),
            status: "stopping".to_string(),
            pid: Some(pid),
        })?;
    } else {
        println!("Stopping {} (pid={})", name, pid);
    }

Ok(())
}

async fn restart_service(service: ServiceKind, cli: &Cli) -> Result<()> {
    stop_service(service.clone(), cli).await?;
    start_service(service, cli).await
}

async fn status(cli: &Cli) -> Result<()> {
    let services = vec![ServiceKind::Backend, ServiceKind::Ui, ServiceKind::Menubar];

let mut statuses = Vec::new();

for svc in services {
        let name = service_name(&svc).to_string();
        let pid_file = pid_file_for(&svc).unwrap();
        let pid = read_pid(pid_file);

let (status, pid) = match pid {
            Some(pid_val) if process_exists(pid_val) => ("running".to_string(), Some(pid_val)),
            Some(_) => {
                // Stale PID file – remove it
                let _ = fs::remove_file(pid_file);
                ("stopped".to_string(), None)
            }
            None => ("stopped".to_string(), None),
        };

statuses.push(ServiceStatus {
            service: name,
            status,
            pid,
        });
    }

let ts = chrono::Utc::now().to_rfc3339();

// Persist status snapshot to STATUS_FILE for compatibility with previous tooling.
    {
        let mut map = load_status_map()?;
        for svc in &statuses {
            let entry = StatusFileEntry {
                status: svc.status.clone(),
                pid: svc.pid,
                timestamp: ts.clone(),
            };
            map.insert(
                svc.service.clone(),
                serde_json::to_value(entry).map_err(|e| {
                    AosError::Config(format!("Failed to encode status entry: {}", e))
                })?,
            );
        }
        write_status_map(&map)?;
    }

let report = StatusReport {
        ts,
        component: "aos",
        services: statuses,
    };

Ok(ModelInfo {
            model_path: self.model_path.clone(),
            vocab_size: config.vocab_size,
            hidden_size: config.hidden_size,
            num_layers: config.num_layers,
            total_parameters: self.estimate_parameter_count(&config),
        })
    }

/// Estimate total parameter count
    fn estimate_parameter_count(&self, config: &QwenModelConfig) -> usize {
        // Embedding layer
        let embedding_params = config.vocab_size * config.hidden_size;

// LM head
        let lm_head_params = config.hidden_size * config.vocab_size;

// Transformer layers (approximate)
        let attention_params = config.num_layers * config.hidden_size * config.hidden_size * 4; // Q, K, V, O
        let mlp_params = config.num_layers * config.hidden_size * config.intermediate_size * 2; // gate, up

embedding_params + lm_head_params + attention_params + mlp_params
    }

/// Estimate memory usage of a loaded model in bytes
    ///
    /// Provides a rough estimate based on parameter count and data types.
    /// This is used for cache memory management and eviction decisions.
    fn estimate_model_memory_usage(&self, model: &QwenModel) -> u64 {
        // Each f32 parameter is 4 bytes
        let bytes_per_param = 4u64;

// Count total parameters
        let total_params = self.estimate_parameter_count(&model.config);

// Calculate base memory usage (parameters only)
        let base_memory = total_params as u64 * bytes_per_param;

// Add overhead for model structure and metadata (~10% overhead)
        let overhead_factor = 1.1;

(base_memory as f64 * overhead_factor) as u64
    }
}

