        assert!(conflict.is_err());

// Complete operation
        tracker
            .complete_operation(
                "model1",
                "tenant1",
                OperationType::Model(ModelOperationType::Load),
                true,
            )
            .await;

// Now unload should work
        tracker
            .start_operation(
                "model1",
                "tenant1",
                OperationType::Model(ModelOperationType::Unload),
            )
            .await
            .expect("Operation should succeed");
    }

