/// Configuration builder for constructing deterministic configs
pub struct ConfigBuilder {
    values: HashMap<String, String>,
    sources: Vec<ConfigSource>,
    schema: ConfigSchema,
    manifest_path: Option<String>,
    cli_args: Vec<String>,
}

impl ConfigBuilder {
    /// Create a new configuration builder
    pub fn new() -> Self {
        Self {
            values: HashMap::new(),
            sources: Vec::new(),
            schema: ConfigSchema::default(),
            manifest_path: None,
            cli_args: Vec::new(),
        }
    }

/// Set the configuration schema
    pub fn with_schema(mut self, schema: ConfigSchema) -> Self {
        self.schema = schema;
        self
    }

/// Add a configuration value with source information
    pub fn add_value(
        mut self,
        key: String,
        value: String,
        level: PrecedenceLevel,
        source: String,
    ) -> Self {
        // Check if key already exists with lower precedence
        if let Some(existing_source) = self.sources.iter().find(|s| s.key == key) {
            if existing_source.level < level {
                // Remove existing lower precedence value
                self.values.remove(&key);
                self.sources.retain(|s| s.key != key);
            } else {
                // Higher precedence value already exists, skip
                return self;
            }
        }

self.values.insert(key.clone(), value.clone());
        self.sources.push(ConfigSource {
            level,
            source,
            key,
            value,
        });

self
    }

/// Set manifest path
    pub fn with_manifest_path(mut self, path: String) -> Self {
        self.manifest_path = Some(path);
        self
    }

/// Set CLI arguments
    pub fn with_cli_args(mut self, args: Vec<String>) -> Self {
        self.cli_args = args;
        self
    }

/// Build the deterministic configuration
    pub fn build(self) -> Result<DeterministicConfig> {
        let mut values = self.values;
        let mut sources = self.sources;
        let schema = self.schema;
        let manifest_path = self.manifest_path;
        let cli_args = self.cli_args;

// Apply schema defaults for missing values up front
        for (key, field_def) in &schema.fields {
            if !values.contains_key(key) {
                if let Some(default_value) = &field_def.default_value {
                    values.insert(key.clone(), default_value.clone());
                    sources.push(ConfigSource {
                        level: PrecedenceLevel::Manifest,
                        source: "default".to_string(),
                        key: key.clone(),
                        value: default_value.clone(),
                    });
                }
            }
        }

impl<K, V, E> Debug for SingleFlight<K, V, E>
where
    K: Eq + Hash + Clone + Send + Sync + 'static,
    V: Clone + Send + Sync + 'static,
    E: Clone + Send + Sync + 'static,
{
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("SingleFlight")
            .field("operation_label", &self.operation_label)
            .field("pending_loads", &self.in_flight.len())
            .finish()
    }
}

/// RAII guard to ensure in-flight entry is cleaned up on cancellation.
struct CleanupGuard<'a, K, V, E>
where
    K: Eq + Hash + Clone + Send + Sync + 'static,
    V: Clone + Send + Sync + 'static,
    E: Clone + Send + Sync + 'static,
{
    in_flight: &'a DashMap<K, Arc<InFlightEntry<V, E>>>,
    key: K,
    entry: Arc<InFlightEntry<V, E>>,
    completed: bool,
}

impl<K, V, E> Drop for CleanupGuard<'_, K, V, E>
where
    K: Eq + Hash + Clone + Send + Sync + 'static,
    V: Clone + Send + Sync + 'static,
    E: Clone + Send + Sync + 'static,
{
    fn drop(&mut self) {
        // If the guard is dropped without completing (i.e., leader was cancelled),
        // we need to notify waiters and clean up.
        // However, since we can't set a result in Drop (we don't have E),
        // we just notify waiters who will see None and handle it.
        if !self.completed && self.entry.result.get().is_none() {
            // Notify waiters that something went wrong
            self.entry.notify.notify_waiters();
            // Remove the in-flight entry
            self.in_flight.remove(&self.key);
        }
    }
}

/// Test that hash collision is extremely unlikely with different content.
///
/// BLAKE3 should provide collision resistance.
#[test]
fn test_hash_collision_resistance() {
    let mut hashes = std::collections::HashSet::new();

// Generate 1000 different payloads and verify no collisions
    for i in 0..1000 {
        let payload = format!("unique-payload-{}", i);
        let hash = B3Hash::hash(payload.as_bytes());
        let inserted = hashes.insert(hash);
        assert!(inserted, "Hash collision detected for payload {}", i);
    }
}

