let mut conflicting_adapters = Vec::new();

for row in rows {
            let other_id: String = row.get(0);
            if other_id == adapter_id {
                // Skip self - re-activation is not a conflict
                continue;
            }

let other_metadata: Option<String> = row.get(1);
            let other_branch = branch_from_metadata(&other_metadata);

// Determine if branches conflict
            let branches_conflict = match (&requested_branch, &other_branch) {
                // Both have explicit branches - conflict only if they match
                (Some(req), Some(other)) => req == other,
                // New adapter has no branch - conflicts with any existing active
                (None, _) => true,
                // Existing has no branch - conflicts with any new activation
                (Some(_), None) => true,
            };

if branches_conflict {
                debug!(
                    adapter_id = %adapter_id,
                    conflicting_adapter = %other_id,
                    repo_id = %repo_id,
                    requested_branch = ?requested_branch,
                    other_branch = ?other_branch,
                    "Single-active conflict detected"
                );
                conflicting_adapters.push(other_id);
            }
        }

if conflicting_adapters.is_empty() {
            Ok(SingleActiveValidationResult::valid())
        } else {
            let branch_desc = requested_branch
                .as_deref()
                .unwrap_or("(unspecified branch)");
            let reason = format!(
                "Cannot activate adapter '{}' for repo '{}' on branch '{}': \
                 adapter(s) {} already active. Only one adapter can be active per repository/branch.",
                adapter_id,
                repo_id,
                branch_desc,
                conflicting_adapters.join(", ")
            );

warn!(
                adapter_id = %adapter_id,
                repo_id = %repo_id,
                conflicting_count = conflicting_adapters.len(),
                "Single-active adapter validation failed"
            );

Ok(SingleActiveValidationResult::conflict(
                conflicting_adapters,
                reason,
            ))
        }
    }

/// Enforce single-active adapter constraint, returning an error on violation
    ///
    /// This is a convenience wrapper around `validate_single_active_per_repo` that
    /// returns an error if the constraint would be violated, making it suitable
    /// for use in activation workflows.
    ///
    /// # Arguments
    /// * `adapter_id` - The adapter ID to validate for activation
    /// * `repo_id` - The repository ID to check against
    /// * `requested_branch` - Optional branch from the adapter's metadata
    ///
    /// # Errors
    /// Returns `AosError::Validation` if another adapter is already active for
    /// the same repository/branch combination.
    ///
    /// # Example
    /// ```no_run
    /// # use adapteros_db::Db;
    /// # async fn example(db: &Db) -> anyhow::Result<()> {
    /// // This will return an error if a conflict exists
    /// db.enforce_single_active_per_repo(
    ///     "adapter-456",
    ///     "repo-123",
    ///     Some("main".to_string()),
    /// ).await?;
    ///
    /// // Safe to activate the adapter now
    /// # Ok(())
    /// # }
    /// ```
    pub async fn enforce_single_active_per_repo(
        &self,
        adapter_id: &str,
        repo_id: &str,
        requested_branch: Option<String>,
    ) -> Result<()> {
        let result = self
            .validate_single_active_per_repo(adapter_id, repo_id, requested_branch)
            .await?;

if !result.is_valid {
            return Err(AosError::Validation(result.conflict_reason.unwrap_or_else(
                || format!("Single-active constraint violated for repo '{}'", repo_id),
            )));
        }

Ok(())
    }

//! System metrics helpers and emitters (placeholder implementation)
//!
//! Provides a minimal, dependency-free placeholder system metrics emitter that
//! produces `system.metrics` events into the unified telemetry NDJSON pipeline.
//!
//! This is intended as a scaffold. Replace the placeholder collectors with a
//! real system metrics collector (e.g., sysinfo) when ready.

use std::sync::Arc;
use std::time::{Duration, SystemTime, UNIX_EPOCH};

use serde_json::json;
use tracing::warn;

/// Build a placeholder `system.metrics` payload.
pub fn placeholder_system_metrics_event() -> crate::event::SystemMetricsEvent {
    crate::event::SystemMetricsEvent {
        cpu_usage: 0.0,
        memory_usage: 0.0,
        disk_read_bytes: 0,
        disk_write_bytes: 0,
        network_rx_bytes: 0,
        network_tx_bytes: 0,
        gpu_utilization: None,
        gpu_memory_used: None,
        uptime_seconds: 0,
        process_count: 0,
        load_average: crate::event::LoadAverageEvent {
            load_1min: 0.0,
            load_5min: 0.0,
            load_15min: 0.0,
        },
        timestamp: SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs(),
    }
}

/// Spawn a background task that periodically emits placeholder `system.metrics` events.
///
/// - `writer`: unified telemetry writer used to append to the NDJSON pipeline
/// - `interval`: how frequently to emit the event
pub fn spawn_placeholder_emitter(
    writer: Arc<crate::TelemetryWriter>,
    interval: Duration,
) -> tokio::task::JoinHandle<()> {
    tokio::spawn(async move {
        let mut ticker = tokio::time::interval(interval);
        loop {
            ticker.tick().await;
            let payload = placeholder_system_metrics_event();
            // Attach payload as metadata on unified telemetry event.
            let metadata = match serde_json::to_value(&payload) {
                Ok(val) => val,
                Err(err) => {
                    warn!("Failed to encode system metrics payload: {}", err);
                    json!({
                        "serialization_error": err.to_string(),
                    })
                }
            };

let identity = adapteros_core::identity::IdentityEnvelope::new(
                "system".to_string(),
                "metrics".to_string(),
                "system-monitoring".to_string(),
                adapteros_core::identity::IdentityEnvelope::default_revision(),
            );
            match crate::TelemetryEventBuilder::new(
                crate::EventType::Custom("metrics.system".to_string()),
                crate::LogLevel::Info,
                "Placeholder system metrics sample".to_string(),
                identity,
            )
            .component("adapteros-server".to_string())
            .metadata(metadata)
            .build()
            {
                Ok(event) => {
                    // Best-effort; keep server hot path resilient.
                    let _ = writer.log_event(event);
                }
                Err(e) => {
                    warn!("Failed to build telemetry event: {}", e);
                    continue;
                }
            }
        }
    })
}

