impl Db {
pub async fn find_adapters_with_missing_hashes(
        &self,
        tenant_id: Option<&str>,
        limit: i64,
    ) -> Result<Vec<Adapter>> {
        let query = match tenant_id {
            Some(_) => format!(
                "SELECT {} FROM adapters
                 WHERE tenant_id = ?
                   AND aos_file_path IS NOT NULL
                   AND aos_file_path != ''
                   AND archived_at IS NULL
                   AND purged_at IS NULL
                   AND (
                       content_hash_b3 IS NULL
                       OR content_hash_b3 = ''
                       OR manifest_hash IS NULL
                       OR manifest_hash = ''
                   )
                 ORDER BY created_at ASC
                 LIMIT ?",
                ADAPTER_SELECT_FIELDS
            ),
            None => format!(
                "SELECT {} FROM adapters
                 WHERE aos_file_path IS NOT NULL
                   AND aos_file_path != ''
                   AND archived_at IS NULL
                   AND purged_at IS NULL
                   AND (
                       content_hash_b3 IS NULL
                       OR content_hash_b3 = ''
                       OR manifest_hash IS NULL
                       OR manifest_hash = ''
                   )
                 ORDER BY created_at ASC
                 LIMIT ?",
                ADAPTER_SELECT_FIELDS
            ),
        };

let adapters = match tenant_id {
            Some(tid) => sqlx::query_as::<_, Adapter>(&query)
                .bind(tid)
                .bind(limit)
                .fetch_all(self.pool())
                .await
                .map_err(|e| {
                    AosError::database(format!(
                        "Failed to find adapters with missing hashes: {}",
                        e
                    ))
                })?,
            None => sqlx::query_as::<_, Adapter>(&query)
                .bind(limit)
                .fetch_all(self.pool())
                .await
                .map_err(|e| {
                    AosError::database(format!(
                        "Failed to find adapters with missing hashes: {}",
                        e
                    ))
                })?,
        };

Ok(adapters)
    }
}

impl Db {
pub async fn list_adapters_for_tenant(&self, tenant_id: &str) -> Result<Vec<Adapter>> {
        self.list_adapters_for_tenant_paged(tenant_id, None, None)
            .await
    }
}

impl Db {
pub async fn list_all_adapters_system(&self) -> Result<Vec<Adapter>> {
        if self.storage_mode().read_from_kv() {
            let mut adapters = Vec::new();

let tenants = self.list_tenants().await?;
            for tenant in tenants {
                let tenant_adapters = self.list_adapters_for_tenant(&tenant.id).await?;
                adapters.extend(tenant_adapters);
            }

if !adapters.is_empty() || !self.storage_mode().sql_fallback_enabled() {
                adapters.sort_by(|a, b| {
                    a.tier
                        .cmp(&b.tier)
                        .then_with(|| b.created_at.cmp(&a.created_at))
                });
                return Ok(adapters);
            }

self.record_kv_read_fallback("adapters.list_all.system");
        }

let query = format!(
            "SELECT {} FROM adapters WHERE active = 1 ORDER BY tier ASC, created_at DESC",
            ADAPTER_SELECT_FIELDS
        );
        let adapters = sqlx::query_as::<_, Adapter>(&query)
            .fetch_all(self.pool())
            .await
            .map_err(|e| {
                AosError::database(format!("Failed to list all adapters (system): {}", e))
            })?;
        Ok(adapters)
    }
}

impl Db {
pub async fn cleanup_orphaned_adapters(&self, tenant_id: &str) -> Result<u64> {
        // Get adapter IDs from SQL
        let sql_adapters = self.list_adapters_for_tenant(tenant_id).await?;
        let sql_ids: std::collections::HashSet<String> = sql_adapters
            .iter()
            .filter_map(|a| a.adapter_id.clone())
            .collect();

// Get adapter IDs from KV
        let kv_repo = match self.get_adapter_kv_repo(tenant_id) {
            Some(repo) => repo,
            None => {
                // No KV repo configured, nothing to clean up
                return Ok(0);
            }
        };

let kv_adapters = kv_repo
            .list_adapters_for_tenant_kv(tenant_id, None, None)
            .await?;
        let kv_ids: std::collections::HashSet<String> = kv_adapters
            .iter()
            .filter_map(|a| a.adapter_id.clone())
            .collect();

// Find orphans: KV entries that don't exist in SQL
        let orphans: Vec<String> = kv_ids.difference(&sql_ids).cloned().collect();

let Some(kv) = self.kv_backend() else {
            return Ok(issues);
        };
        let repo = AuthSessionKvRepository::new(kv.backend().clone());

for row in sql_sessions {
            let kv_session = repo.get_session(&row.jti).await?;
            match kv_session {
                Some(sess) => {
                    if sess.user_id != row.user_id {
                        issues.push(DiffIssue {
                            domain: "auth_sessions".into(),
                            id: row.jti.clone(),
                            field: "user_id".into(),
                            sql_value: row.user_id.clone(),
                            kv_value: sess.user_id.clone(),
                        });
                    }
                    if sess.tenant_id.as_deref() != row.tenant_id.as_deref() {
                        issues.push(DiffIssue {
                            domain: "auth_sessions".into(),
                            id: row.jti.clone(),
                            field: "tenant_id".into(),
                            sql_value: row.tenant_id.clone().unwrap_or_else(|| "None".into()),
                            kv_value: sess.tenant_id.clone().unwrap_or_else(|| "None".into()),
                        });
                    }
                    if sess.ip_address != row.ip_address {
                        issues.push(DiffIssue {
                            domain: "auth_sessions".into(),
                            id: row.jti.clone(),
                            field: "ip_address".into(),
                            sql_value: row.ip_address.clone().unwrap_or_else(|| "None".into()),
                            kv_value: sess.ip_address.clone().unwrap_or_else(|| "None".into()),
                        });
                    }
                    if sess.user_agent != row.user_agent {
                        issues.push(DiffIssue {
                            domain: "auth_sessions".into(),
                            id: row.jti.clone(),
                            field: "user_agent".into(),
                            sql_value: row.user_agent.clone().unwrap_or_else(|| "None".into()),
                            kv_value: sess.user_agent.clone().unwrap_or_else(|| "None".into()),
                        });
                    }
                    let sql_expires = DateTime::parse_from_rfc3339(&row.expires_at)
                        .map(|dt| dt.timestamp())
                        .or_else(|_| row.expires_at.parse::<i64>().map_err(|_| ()))
                        .unwrap_or_else(|_| Utc::now().timestamp());
                    if sess.expires_at != sql_expires {
                        issues.push(DiffIssue {
                            domain: "auth_sessions".into(),
                            id: row.jti.clone(),
                            field: "expires_at".into(),
                            sql_value: sql_expires.to_string(),
                            kv_value: sess.expires_at.to_string(),
                        });
                    }
                }
                None => issues.push(DiffIssue {
                    domain: "auth_sessions".into(),
                    id: row.jti.clone(),
                    field: "_existence".into(),
                    sql_value: "present".into(),
                    kv_value: "missing".into(),
                }),
            }
        }

Ok(issues)
    }

pub async fn diff_runtime_sessions(&self) -> adapteros_core::Result<Vec<DiffIssue>> {
        let mut issues = Vec::new();
        let Some(pool) = self.pool_opt() else {
            return Ok(issues);
        };

#[derive(sqlx::FromRow)]
        struct RuntimeRow {
            id: String,
            session_id: String,
            config_hash: String,
            binary_version: String,
            binary_commit: Option<String>,
            started_at: String,
            #[allow(dead_code)]
            ended_at: Option<String>,
            #[allow(dead_code)]
            end_reason: Option<String>,
            hostname: String,
            runtime_mode: String,
            drift_detected: i64,
        }

let mut rows = sqlx::query_as::<_, RuntimeRow>(
            r#"
            SELECT id, session_id, config_hash, binary_version, binary_commit, started_at, ended_at,
                   end_reason, hostname, runtime_mode, drift_detected
            FROM runtime_sessions
            ORDER BY started_at DESC, id ASC
            "#,
        )
        .fetch_all(pool)
        .await?;

rows.sort_by(|a, b| {
            b.started_at
                .cmp(&a.started_at)
                .then_with(|| a.id.cmp(&b.id))
        });

let Some(kv) = self.kv_backend() else {
