/// Dequantize MLX 4-bit quantized embeddings
    fn dequantize_mlx_4bit(
        packed_data: &[u8],
        scales_data: &[u8],
        biases_data: &[u8],
        vocab_size: usize,
        hidden_dim: usize,
        group_size: usize,
    ) -> Result<Vec<f32>> {
        let num_groups = hidden_dim / group_size;
        let mut result = Vec::with_capacity(vocab_size * hidden_dim);

// Parse scales and biases as fp16
        let scales: Vec<f32> = scales_data
            .chunks_exact(2)
            .map(|chunk| {
                let bits = u16::from_le_bytes([chunk[0], chunk[1]]);
                half::f16::from_bits(bits).to_f32()
            })
            .collect();

let biases: Vec<f32> = biases_data
            .chunks_exact(2)
            .map(|chunk| {
                let bits = u16::from_le_bytes([chunk[0], chunk[1]]);
                half::f16::from_bits(bits).to_f32()
            })
            .collect();

// 4-bit packing: 2 values per byte
        let packed_per_row = hidden_dim / 2;

for vocab_idx in 0..vocab_size {
            let row_offset = vocab_idx * packed_per_row;
            let scale_offset = vocab_idx * num_groups;

for group_idx in 0..num_groups {
                let scale = scales.get(scale_offset + group_idx).copied().unwrap_or(1.0);
                let bias = biases.get(scale_offset + group_idx).copied().unwrap_or(0.0);

for elem_in_group in 0..group_size {
                    let elem_idx = group_idx * group_size + elem_in_group;
                    let packed_idx = row_offset + elem_idx / 2;

if packed_idx >= packed_data.len() {
                        result.push(0.0);
                        continue;
                    }

let packed_byte = packed_data[packed_idx];
                    let value = if elem_idx.is_multiple_of(2) {
                        (packed_byte & 0x0F) as f32
                    } else {
                        ((packed_byte >> 4) & 0x0F) as f32
                    };

// Dequantize: scale * (value - 8) + bias (center around 8 for 4-bit)
                    let dequantized = scale * (value - 8.0) + bias;
                    result.push(dequantized);
                }
            }
        }

Ok(result)
    }

/// Deprecated: Use `RealBackendAdapterBackend` instead
///
/// Generic kernel-based execution backend for advanced use cases.
/// This type remains for backwards compatibility with code using the `AdapterLookup` trait.
///
/// # Migration Guide
///
/// If you have code like:
/// ```ignore
/// let backend = KernelAdapterBackend::new(
///     kernels_arc.clone(),
///     lookup_arc,
///     adapter_names.clone(),
///     152064
/// );
/// ```
///
/// Replace with:
/// ```ignore
/// // For automatic backend selection:
/// let backend = RealBackendAdapterBackend::new_auto(
///     adapter_names,
///     152064
/// ).await?;
///
/// // Or for specific backend:
/// let backend = RealBackendAdapterBackend::new_metal(
///     adapter_names,
///     152064
/// ).await?;
/// ```
///
/// The new `RealBackendAdapterBackend` integrates with direct kernel creation
/// for automatic capability detection and backend selection.
pub struct KernelAdapterBackend<K: FusedKernels, L: AdapterLookup> {
    /// Adapter lookup (abstracts AdapterTable)
    lookup: Arc<L>,
    /// Fused kernels for execution
    kernels: Arc<Mutex<K>>,
    /// Adapter name to routing index mapping
    adapter_name_to_index: HashMap<String, u16>,
    /// Vocabulary size for output buffers
    vocab_size: usize,
}

impl<K: FusedKernels, L: AdapterLookup> KernelAdapterBackend<K, L> {
    /// Create a new kernel adapter backend
    ///
    /// # Deprecated
    /// Use `RealBackendAdapterBackend::new_auto()` or similar instead.
    ///
    /// # Arguments
    /// * `kernels` - Fused kernels for GPU execution
    /// * `lookup` - Adapter lookup implementation
    /// * `adapter_names` - List of adapter names in routing order
    /// * `vocab_size` - Model vocabulary size
    #[deprecated(
        since = "0.1.0",
        note = "Use RealBackendAdapterBackend::new_auto() instead"
    )]
    pub fn new(
        kernels: Arc<Mutex<K>>,
        lookup: Arc<L>,
        adapter_names: Vec<String>,
        vocab_size: usize,
    ) -> Self {
        let adapter_name_to_index: HashMap<String, u16> = adapter_names
            .into_iter()
            .enumerate()
            .map(|(i, name)| (name, i as u16))
            .collect();

Self {
            lookup,
            kernels,
            adapter_name_to_index,
            vocab_size,
        }
    }
}

impl<K: FusedKernels + 'static, L: AdapterLookup + 'static> AdapterExecutionBackend
    for KernelAdapterBackend<K, L>
{
    async fn execute_adapter(
        &self,
        adapter_id: &str,
        input_tokens: &[u32],
        _model_state: &HashMap<String, Vec<f32>>,
    ) -> Result<AdapterExecutionResult> {
        // Get adapter index for routing
        let adapter_index = self
            .adapter_name_to_index
            .get(adapter_id)
            .copied()
            .or_else(|| self.lookup.get_adapter_index(adapter_id))
            .ok_or_else(|| {
                adapteros_core::AosError::NotFound(format!("Adapter not found: {}", adapter_id))
            })?;

execute_adapter_with_kernel(
            &self.kernels,
            adapter_index,
            adapter_id,
            input_tokens,
            self.vocab_size,
        )
        .await
    }
}
