// Helper functions extracted from mod.rs
fn normalize_optional_value(value: Option<&str>) -> Option<String> {
    sanitize_optional(value)
}

fn normalize_session_tags(tags: Option<&[String]>) -> Option<String> {
    let tags = tags?;
    let mut normalized: Vec<String> = tags
        .iter()
        .filter_map(|tag| {
            let trimmed = tag.trim();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed.to_string())
            }
        })
        .collect();
    normalized.sort();
    normalized.dedup();
    if normalized.is_empty() {
        None
    } else {
        Some(normalized.join(","))
    }
}

fn parse_scan_roots_from_metadata_json(metadata_json: Option<&str>) -> Vec<ScanRootInput> {
    let raw = match metadata_json {
        Some(raw) if !raw.trim().is_empty() => raw,
        _ => return Vec::new(),
    };

let value: serde_json::Value = match serde_json::from_str(raw) {
        Ok(val) => val,
        Err(_) => return Vec::new(),
    };

if let Some(scan_roots) = value.get("scan_roots") {
        if let Ok(parsed) = serde_json::from_value::<Vec<ScanRootInput>>(scan_roots.clone()) {
            let roots: Vec<ScanRootInput> = parsed
                .into_iter()
                .filter_map(|mut root| {
                    let trimmed = root.path.trim();
                    if trimmed.is_empty() {
                        return None;
                    }
                    if trimmed != root.path {
                        root.path = trimmed.to_string();
                    }
                    Some(root)
                })
                .collect();
            if !roots.is_empty() {
                return roots;
            }
        }
    }

Vec::new()
}

fn parse_metadata_json(metadata_json: Option<&str>) -> Option<Value> {
    let raw = metadata_json?;
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return None;
    }
    serde_json::from_str(trimmed).ok()
}

fn parse_repo_scope_from_value(value: &Value) -> Option<RepoScopeInput> {
    if let Some(scope_value) = value.get("repo_scope") {
        return serde_json::from_value(scope_value.clone()).ok();
    }

value
        .get("repo_scope_json")
        .and_then(|raw| raw.as_str())
        .and_then(|raw| serde_json::from_str::<RepoScopeInput>(raw).ok())
}

fn compute_scope_suffix(metadata_json: Option<&str>) -> Option<String> {
    let metadata = parse_metadata_json(metadata_json)?;
    let repo_scope = parse_repo_scope_from_value(&metadata);
    let scan_roots = parse_scan_roots_from_metadata_json(metadata_json);

let scan_root_relative = metadata
        .get("scan_root_relative")
        .and_then(|v| v.as_str())
        .map(|v| v.trim())
        .filter(|v| !v.is_empty())
        .map(|v| v.to_string());

let repo_root_path = metadata
        .get("repo_root_path")
        .and_then(|v| v.as_str())
        .map(|v| v.trim())
        .filter(|v| !v.is_empty())
        .map(|v| v.to_string());

let mut scan_root_paths: Vec<String> = if !scan_roots.is_empty() {
        scan_roots.into_iter().map(|root| root.path).collect()
    } else {
        metadata
            .get("scan_root_path")
            .and_then(|v| v.as_str())
            .map(|v| v.to_string())
            .into_iter()
            .collect()
    };

scan_root_paths.retain(|p| !p.trim().is_empty());

let repo_scope_active = repo_scope.as_ref().is_some_and(RepoScopeInput::has_filters);
    let scan_root_scoped = if scan_root_paths.len() > 1 || scan_root_relative.is_some() {
        true
    } else if let (Some(root), Some(scan_root)) =
        (repo_root_path.as_deref(), scan_root_paths.first())
    {
        root != scan_root
    } else {
        false
    };

if !repo_scope_active && !scan_root_scoped {
        return None;
    }

let mut hasher = blake3::Hasher::new();
    if let Some(scope) = repo_scope {
        let normalized = scope.normalized();
        if let Ok(scope_json) = serde_json::to_string(&normalized) {
            hasher.update(scope_json.as_bytes());
        }
    }

if !scan_root_paths.is_empty() {
        scan_root_paths.sort();
        scan_root_paths.dedup();
        let joined = scan_root_paths.join("|");
        hasher.update(joined.as_bytes());
    }

if let Some(relative) = scan_root_relative {
        hasher.update(relative.as_bytes());
    }

let hash = hasher.finalize().to_hex().to_string();
    Some(format!("scope-{}", &hash[..8]))
}

//! Chaos Mode: intentionally injects jitter into layer loading to verify synchronization.
//!
//! Enabled via `AOS_WORKER_CHAOS_MODE=1` (or `true/yes`). Optional
//! `AOS_CHAOS_SEED=<u64>` makes the jitter deterministic for tests.

use adapteros_core::{derive_seed, B3Hash};
use rand::{Rng, SeedableRng};
use rand_chacha::ChaCha8Rng;
use std::sync::{Mutex, OnceLock};
use std::time::Duration;
use tracing::debug;

#[derive(Debug, Clone, Copy)]
struct ChaosConfig {
    enabled: bool,
    min_delay_ms: u64,
    max_delay_ms: u64,
    seed: Option<u64>,
}

impl ChaosConfig {
    fn from_env() -> Self {
        let enabled = std::env::var("AOS_WORKER_CHAOS_MODE")
            .map(|v| {
                v.eq_ignore_ascii_case("1")
                    || v.eq_ignore_ascii_case("true")
                    || v.eq_ignore_ascii_case("yes")
            })
            .unwrap_or(false);

let seed = std::env::var("AOS_CHAOS_SEED")
            .ok()
            .and_then(|s| s.parse::<u64>().ok());

Self {
            enabled,
            min_delay_ms: 1,
            max_delay_ms: 50,
            seed,
        }
    }
}

fn chaos_config() -> &'static ChaosConfig {
    static CONFIG: OnceLock<ChaosConfig> = OnceLock::new();
    CONFIG.get_or_init(ChaosConfig::from_env)
}

fn determinism_debug_enabled() -> bool {
    static FLAG: OnceLock<bool> = OnceLock::new();
    *FLAG.get_or_init(|| match std::env::var("AOS_DEBUG_DETERMINISM") {
        Ok(v) => {
            let normalized = v.to_ascii_lowercase();
            normalized == "1" || normalized == "true" || normalized == "yes"
        }
        Err(_) => false,
    })
}

fn seeded_rng(seed: [u8; 32]) -> &'static Mutex<ChaCha8Rng> {
    static RNG: OnceLock<Mutex<ChaCha8Rng>> = OnceLock::new();
    RNG.get_or_init(|| Mutex::new(ChaCha8Rng::from_seed(seed)))
}

fn derived_seed_bytes(cfg: &ChaosConfig) -> [u8; 32] {
    static DERIVED_SEED: OnceLock<[u8; 32]> = OnceLock::new();

*DERIVED_SEED.get_or_init(|| {
        let base_seed = if let Some(seed_override) = cfg.seed {
            B3Hash::hash(&seed_override.to_le_bytes())
        } else {
            B3Hash::hash(b"adapteros-lora-worker:chaos-mode")
        };

let derived = derive_seed(&base_seed, "layer-jitter");

if determinism_debug_enabled() {
            let base_hex = base_seed.to_hex();
            let derived_hex = B3Hash::hash(&derived).to_hex();
            tracing::info!(
                target: "determinism",
                chaos_seed_override = cfg.seed,
                base_seed_prefix = %base_hex.get(..16).unwrap_or(&base_hex),
                derived_prefix = %derived_hex.get(..16).unwrap_or(&derived_hex),
                "Chaos Mode derived seed via HKDF layer-jitter"
            );
        }

derived
    })
}

fn sample_delay_ms(cfg: &ChaosConfig) -> u64 {
    if !cfg.enabled {
        return 0;
    }

let seed = derived_seed_bytes(cfg);
    let rng = seeded_rng(seed);
    let mut guard = rng.lock().expect("chaos rng poisoned");
    guard.gen_range(cfg.min_delay_ms..=cfg.max_delay_ms)
}

/// Returns true if Chaos Mode is enabled.
pub fn chaos_mode_enabled() -> bool {
    chaos_config().enabled
}

/// If Chaos Mode is enabled, sleep for a random 1–50ms to mimic jittery layer loads.
pub fn maybe_delay_layer(layer_idx: usize) {
    let cfg = chaos_config();
    if !cfg.enabled {
        return;
    }

let delay_ms = sample_delay_ms(cfg);
    if delay_ms == 0 {
        return;
    }

debug!(
        layer = layer_idx,
        delay_ms, "Chaos Mode: injecting layer load jitter"
    );
    std::thread::sleep(Duration::from_millis(delay_ms));
}

