            let segment_id = u32::from_le_bytes(entry[0..4].try_into().unwrap());
            let backend_tag_raw = u16::from_le_bytes(entry[4..6].try_into().unwrap());
            let offset = u64::from_le_bytes(entry[8..16].try_into().unwrap()) as usize;
            let len = u64::from_le_bytes(entry[16..24].try_into().unwrap()) as usize;
            let mut scope_hash = [0u8; 16];
            scope_hash.copy_from_slice(&entry[24..40]);
            let mut weights_hash = [0u8; 32];
            weights_hash.copy_from_slice(&entry[40..72]);

assert_eq!(segment_id as usize, i);
            assert_eq!(
                BackendTag::try_from(backend_tag_raw).unwrap(),
                *expected_tag
            );
            assert_eq!(&data[offset..offset + len], *expected_bytes);
            let expected_hash = B3Hash::hash(expected_bytes);
            assert_eq!(expected_hash.as_bytes(), &weights_hash);

if i == 0 {
                // canonical segment had a scope path
                assert_ne!(scope_hash, [0u8; 16]);
            }
        }

Ok(())
    }

#[test]
    fn test_magic_validation() {
        let temp_root = std::path::PathBuf::from("var/tmp");
        std::fs::create_dir_all(&temp_root).unwrap();
        let temp_file = NamedTempFile::new_in(&temp_root).unwrap();

// Write full header with invalid magic bytes
        let mut invalid_header = vec![0u8; HEADER_SIZE];
        invalid_header[0..4].copy_from_slice(b"BAD!");
        std::fs::write(temp_file.path(), &invalid_header).unwrap();

let result = AosWriter::read_header(temp_file.path());
        assert!(result.is_err());
        assert!(result
            .unwrap_err()
            .to_string()
            .contains("invalid AOS magic"));
    }

#[test]
    fn test_header_size_is_64_bytes() {
        assert_eq!(HEADER_SIZE, 64);
    }
}

//! Progress indicators for CLI operations
//!
//! Provides spinners for indeterminate operations (HTTP requests, connecting)
//! and progress bars for determinate operations (training, batch processing).
//!
//! All progress indicators respect OutputWriter modes:
//! - Text mode: Full progress display with animations
//! - JSON mode: No output (silent)
//! - Quiet mode: No output (silent)

use crate::output::OutputWriter;
use indicatif::{ProgressBar, ProgressStyle};
use owo_colors::OwoColorize;
use std::borrow::Cow;
use std::time::Duration;

/// Pre-defined templates for common operations
#[derive(Debug, Clone)]
pub enum ProgressTemplate {
    /// Training progress: [00:15:32] 42/100 epochs (loss: 0.0234)
    Training,
    /// Deployment: [00:01:23] 3/5 adapters (deploying: python-lora)
    Deployment,
    /// Verification: [00:00:45] 150/500 files (validating hashes)
    Verification,
    /// Generic items: [00:00:12] 42/100 items
    Items,
    /// Custom template string (indicatif format)
    Custom(String),
}

impl ProgressTemplate {
    fn to_style(&self) -> ProgressStyle {
        let template = match self {
            Self::Training => {
                "{spinner:.cyan} [{elapsed_precise}] {bar:40.cyan/blue} {pos}/{len} epochs ({msg})"
            }
            Self::Deployment => {
                "{spinner:.green} [{elapsed_precise}] {bar:40.green/blue} {pos}/{len} adapters ({msg})"
            }
            Self::Verification => {
                "{spinner:.yellow} [{elapsed_precise}] {bar:40.yellow/blue} {pos}/{len} files ({msg})"
            }
            Self::Items => {
                "{spinner:.cyan} [{elapsed_precise}] {bar:40.cyan/blue} {pos}/{len} items ({msg})"
            }
            Self::Custom(t) => t.as_str(),
        };

ProgressStyle::with_template(template)
            .expect("valid progress template")
            .progress_chars("=>-")
    }
}

/// Spinner for indeterminate operations (HTTP requests, connecting, etc.)
///
/// Automatically disabled in JSON/Quiet modes. Provides animated feedback
/// for operations where the total duration is unknown.
///
/// # Example
///
/// ```ignore
/// let spinner = Spinner::new(&output, "Connecting to server...");
/// let result = client.connect().await;
/// match result {
///     Ok(_) => spinner.finish_success("Connected"),
///     Err(e) => spinner.finish_error(&format!("Connection failed: {}", e)),
/// }
/// ```
pub struct Spinner {
    pb: Option<ProgressBar>,
}

impl Spinner {
    /// Create a new spinner with the given message.
    ///
    /// Returns a no-op spinner if output mode is JSON or Quiet.
    pub fn new(output: &OutputWriter, message: impl Into<String>) -> Self {
        if output.is_json() || output.is_quiet() {
            return Self { pb: None };
        }

let pb = ProgressBar::new_spinner();
        pb.set_style(
            ProgressStyle::with_template("{spinner:.cyan} {msg}")
                .expect("valid spinner template")
                .tick_strings(&["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]),
        );
        pb.set_message(message.into());
        pb.enable_steady_tick(Duration::from_millis(80));

Self { pb: Some(pb) }
    }

/// Update the spinner message.
    pub fn set_message(&self, msg: impl Into<Cow<'static, str>>) {
        if let Some(pb) = &self.pb {
            pb.set_message(msg);
        }
    }

/// Finish with a success message (green checkmark).
    pub fn finish_success(&self, msg: impl AsRef<str>) {
        if let Some(pb) = &self.pb {
            pb.finish_and_clear();
            println!("{} {}", "✓".green(), msg.as_ref());
        }
    }

Ok(results)
    }

/// Query policy decisions with filters
    ///
    /// Returns policy audit decisions matching the provided filters.
    /// All filters are optional and combined with AND logic.
    ///
    /// # Arguments
    /// * `filters` - Query filters (tenant_id, policy_pack_id, hook, decision, time range, pagination)
    ///
    /// # Returns
    /// Vector of matching policy audit decisions, ordered by timestamp descending
    ///
    /// # Example
    /// ```no_run
    /// use adapteros_db::{Db, PolicyDecisionFilters};
    ///
    /// # async fn example(db: &Db) -> anyhow::Result<()> {
    /// let filters = PolicyDecisionFilters {
    ///     tenant_id: Some("tenant-123".to_string()),
    ///     decision: Some("deny".to_string()),
    ///     from_time: Some("2025-01-01T00:00:00Z".to_string()),
    ///     limit: Some(100),
    ///     ..Default::default()
    /// };
    ///
    /// let decisions = db.query_policy_decisions(filters).await?;
    /// for decision in decisions {
    ///     println!("Policy {} {} at {}: {}",
    ///         decision.policy_pack_id,
    ///         decision.decision,
    ///         decision.hook,
    ///         decision.reason.unwrap_or_default()
    ///     );
    /// }
    /// # Ok(())
    /// # }
    /// ```
    pub async fn query_policy_decisions(
        &self,
        filters: PolicyDecisionFilters,
    ) -> Result<Vec<PolicyAuditDecision>> {
        if self.storage_mode().read_from_kv() {
            if let Some(repo) = self.get_policy_audit_kv_repo() {
                let res = repo.query_policy_decisions(filters.clone()).await?;
                if !self.storage_mode().sql_fallback_enabled() || !res.is_empty() {
                    return Ok(res);
                }
            }
        }

if !self.storage_mode().read_from_sql() {
            return Ok(Vec::new());
        }

// Enforce maximum limit
        let limit = filters.limit.unwrap_or(100).min(1000);

// Use FilterBuilder to construct dynamic query
        let mut builder = FilterBuilder::new(
            "SELECT id, tenant_id, policy_pack_id, hook, decision, reason, request_id, user_id,
                    resource_type, resource_id, metadata_json, timestamp, entry_hash, previous_hash, chain_sequence
             FROM policy_audit_decisions WHERE 1=1",
        );

// Apply optional filters
        if let Some(tid) = &filters.tenant_id {
            builder.push_str(" AND tenant_id = ?");
            builder.add_param(tid);
        }

if let Some(pid) = &filters.policy_pack_id {
            builder.push_str(" AND policy_pack_id = ?");
            builder.add_param(pid);
        }

if let Some(hook) = &filters.hook {
            builder.push_str(" AND hook = ?");
            builder.add_param(hook);
        }

if let Some(decision) = &filters.decision {
            builder.push_str(" AND decision = ?");
            builder.add_param(decision);
        }

// Handle timestamp filters with custom operators
        if let Some(from) = &filters.from_time {
            builder.push_str(" AND timestamp >= ?");
            builder.add_param(from);
        }
        if let Some(to) = &filters.to_time {
            builder.push_str(" AND timestamp <= ?");
            builder.add_param(to);
        }

builder.push_str(" ORDER BY timestamp DESC LIMIT ?");
        builder.add_param(limit);

if let Some(offset) = filters.offset {
            builder.push_str(" OFFSET ?");
            builder.add_param(offset);
        }

// Build and execute query
        let mut q = sqlx::query_as::<_, PolicyAuditDecision>(builder.query());
        for param in builder.params() {
            q = q.bind(param);
        }

let decisions = q
            .fetch_all(self.pool())
            .await
            .map_err(db_err("query policy decisions"))?;
        Ok(decisions)
    }
}

