/// Derive a deterministic seed with an index for array-like derivations
///
/// Allows deriving multiple seeds for the same component by index
pub fn derive_seed_indexed(global: &B3Hash, label: &str, index: usize) -> [u8; 32] {
    let indexed_label = format!("{}:{}", label, index);
    derive_seed(global, &indexed_label)
}

/// Derive a request-scoped seed with configurable determinism mode.
///
/// Seed label includes:
/// - manifest hash (or tenant-scoped fallback when absent)
/// - tenant id
/// - request id
/// - worker id
/// - nonce
///
/// This makes it explicit that re-running the same request on a different
/// worker yields a different seed, while the exact same tuple reproduces.
pub fn derive_request_seed(
    global: &B3Hash,
    manifest: Option<&B3Hash>,
    tenant_id: &str,
    request_id: &str,
    worker_id: u32,
    nonce: u64,
    mode: SeedMode,
) -> Result<[u8; 32]> {
    if matches!(mode, SeedMode::NonDeterministic) && is_strict_determinism_mode() {
        return Err(AosError::DeterminismViolation(
            "NonDeterministic seed_mode is not permitted when strict determinism is enabled"
                .to_string(),
        ));
    }
    match mode {
        SeedMode::Strict => {
            let manifest_hash = manifest.ok_or_else(|| {
                AosError::DeterminismViolation(
                    "Strict seed_mode requires manifest hash".to_string(),
                )
            })?;
            if determinism_debug_enabled() {
                let manifest_hex = manifest_hash.to_hex();
                tracing::info!(
                    target: "determinism",
                    mode = %mode,
                    tenant_id,
                    request_id,
                    worker_id,
                    nonce,
                    manifest_prefix = %manifest_hex.get(..16).unwrap_or(&manifest_hex),
                    "Deriving strict request seed (AOS_DEBUG_DETERMINISM=1)"
                );
            }
            let label = format!(
                "request:{}:{}:{}:{}:{}",
                manifest_hash.to_hex(),
                tenant_id,
                request_id,
                worker_id,
                nonce
            );
            Ok(derive_seed(global, &label))
        }
        SeedMode::BestEffort => {
            // Check if manifest is missing (fallback case)
            let fallback_used = manifest.is_none();

if fallback_used {
                // Log fallback usage for observability (PRD requirement: log all fallback uses)
                tracing::warn!(
                    target: "determinism",
                    tenant_id,
                    request_id,
                    worker_id,
                    nonce,
                    "BestEffort seed fallback: no manifest provided, using tenant-scoped hash"
                );

// In strict determinism mode, fallback is a policy violation
                if is_strict_determinism_mode() {
                    // Emit telemetry event before failing
                    let event = crate::telemetry::strict_mode_failure_event(
                        "BestEffort seed fallback attempted without manifest in strict mode",
                        Some("seed.fallback".to_string()),
                        true, // fallback_used
                        Some(tenant_id.to_string()),
                        Some(request_id.to_string()),
                    );
                    crate::telemetry::emit_observability_event(&event);

return Err(AosError::DeterminismViolation(
                        "BestEffort seed fallback is not permitted when strict determinism is enabled. \
                         Provide a manifest hash or use NonDeterministic mode (debug only)."
                            .to_string(),
                    ));
                }
            }

use crate::unified_memory::{BackendStats, MemoryStats};
use std::collections::HashMap;

/// Report describing current memory pressure across backends.
#[derive(Debug, Clone, PartialEq)]
pub struct MemoryPressureReport {
    /// Total allocated bytes across the system.
    pub total_allocated: usize,
    /// Global memory limit.
    pub memory_limit: usize,
    /// Global pressure percentage (0-100).
    pub pressure_pct: f32,
    /// Per backend pressure percentages.
    pub backend_pressure: HashMap<String, f32>,
    /// Fragmentation score (0-1) computed from backend variance.
    pub fragmentation: f32,
}

/// Action the optimizer recommends for improving memory health.
#[derive(Debug, Clone, PartialEq)]
pub enum MemoryOptimizationAction {
    /// Rebalance memory from one backend to another.
    Rebalance {
        from: String,
        to: String,
        bytes: usize,
    },
    /// Release cold buffers from a backend.
    EvictCold { backend: String, bytes: usize },
    /// Trigger in place compaction for a backend.
    Compact { backend: String },
    /// Expand a backend pool when pressure is low but fragmentation is high.
    ExpandPool {
        backend: String,
        additional_bytes: usize,
    },
}

/// Optimization plan produced by [`MemoryOptimizer`].
#[derive(Debug, Clone, PartialEq)]
pub struct MemoryOptimizationPlan {
    /// Ordered list of optimization actions.
    pub actions: Vec<MemoryOptimizationAction>,
    /// Target fragmentation score after executing the plan.
    pub target_fragmentation: f32,
    /// Target pressure percentage after executing the plan.
    pub target_pressure_pct: f32,
}

/// Production memory optimizer that balances fragmentation, pressure, and determinism.
#[derive(Debug, Clone)]
pub struct MemoryOptimizer {
    pressure_threshold_pct: f32,
    fragmentation_threshold: f32,
    rebalance_granularity: usize,
}

impl MemoryOptimizer {
    /// Create a new optimizer.
    pub fn new(
        pressure_threshold_pct: f32,
        fragmentation_threshold: f32,
        rebalance_granularity: usize,
    ) -> Self {
        Self {
            pressure_threshold_pct: pressure_threshold_pct.clamp(10.0, 100.0),
            fragmentation_threshold: fragmentation_threshold.clamp(0.0, 1.0),
            rebalance_granularity: rebalance_granularity.max(1 << 20), // minimum 1 MiB granularity
        }
    }

/// Analyse raw memory stats and produce a pressure report.
    pub fn analyse(&self, stats: &MemoryStats) -> MemoryPressureReport {
        let pressure_pct = if stats.memory_limit == 0 {
            0.0
        } else {
            (stats.total_allocated as f32 / stats.memory_limit as f32 * 100.0).min(100.0)
        };

let backend_pressure = stats
            .backend_stats
            .iter()
            .map(|(backend, backend_stats)| {
                let pct = Self::backend_pressure_pct(backend_stats);
                (backend.clone(), pct)
            })
            .collect::<HashMap<_, _>>();

let fragmentation = Self::compute_fragmentation(&backend_pressure);

MemoryPressureReport {
            total_allocated: stats.total_allocated,
            memory_limit: stats.memory_limit,
            pressure_pct,
            backend_pressure,
            fragmentation,
        }
    }

/// Generate an optimisation plan using the provided stats.
    pub fn plan(&self, stats: &MemoryStats) -> MemoryOptimizationPlan {
        let report = self.analyse(stats);
        let mut actions = Vec::new();

// Evict cold buffers when global pressure breaches the threshold.
        if report.pressure_pct >= self.pressure_threshold_pct {
            if let Some((backend, _pressure)) = report
                .backend_pressure
                .iter()
                .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
            {
                let evict_bytes = (stats
                    .backend_stats
                    .get(backend)
                    .map(|s| s.allocated)
                    .unwrap_or(0)
                    / 4)
                .max(self.rebalance_granularity);
                actions.push(MemoryOptimizationAction::EvictCold {
                    backend: backend.clone(),
                    bytes: evict_bytes,
                });

/// Train LoRA adapter on examples with GPU acceleration (if available)
    ///
    /// This method provides backward compatibility with automatic progress callback.
    /// For more control, use `train_with_callback` instead.
    pub async fn train(&mut self, examples: &[TrainingExample]) -> Result<TrainingResult> {
        // Backward-compatible behavior: no external progress callback
        self.train_with_callback(examples, |_| {}).await
    }

/// Train with automatic checkpoint resume
    ///
    /// If a checkpoint exists, resumes from the saved state. Otherwise starts fresh.
    /// This method automatically enables checkpointing if configured.
    pub async fn train_with_resume<C>(
        &mut self,
        examples: &[TrainingExample],
        on_epoch: C,
    ) -> Result<TrainingResult>
    where
        C: FnMut(EpochMetrics),
    {
        self.train_with_resume_state(examples, on_epoch, None).await
    }

/// Train with optional preloaded resume state.
    pub async fn train_with_resume_state<C>(
        &mut self,
        examples: &[TrainingExample],
        on_epoch: C,
        resume_state: Option<TrainingCheckpoint>,
    ) -> Result<TrainingResult>
    where
        C: FnMut(EpochMetrics),
    {
        let mut resume_state = resume_state;
        let loaded_internally = resume_state.is_none();
        if loaded_internally {
            // Try to resume from checkpoint
            resume_state = self.try_resume_from_checkpoint().await?;
        }

let prepared_dataset = self.prepare_datasets_for_training(examples)?;

if let Some(checkpoint) = resume_state {
            if loaded_internally {
                info!(
                    start_epoch = checkpoint.epoch,
                    config = %checkpoint.config.summary(),
                    "Resuming training from checkpoint"
                );
            }
            // Restore optimizer state if present (for multi-module training)
            if let Some(ref opt_state) = checkpoint.multi_module_optimizer_state {
                self.multi_module_optimizer = opt_state.clone();
                info!(
                    modules = opt_state.module_states.len(),
                    "Restored multi-module optimizer state from checkpoint"
                );
            } else if self.config.multi_module_training {
                warn!(
                    "Multi-module training enabled but checkpoint has no optimizer state. \
                     Adam momentum will start fresh."
                );
            }
            self.run_training(
                prepared_dataset,
                checkpoint.epoch as usize,
                Some(checkpoint.weights),
                on_epoch,
            )
            .await
        } else {
            self.run_training(prepared_dataset, 0, None, on_epoch).await
        }
    }

/// Train with automatic checkpoint resume using pre-split datasets.
    pub async fn train_with_resume_split<C>(
        &mut self,
        train_examples: &[TrainingExample],
        validation_examples: &[TrainingExample],
        on_epoch: C,
    ) -> Result<TrainingResult>
    where
        C: FnMut(EpochMetrics),
    {
        self.train_with_resume_split_state(train_examples, validation_examples, on_epoch, None)
            .await
    }

/// Train with optional preloaded resume state using pre-split datasets.
    pub async fn train_with_resume_split_state<C>(
        &mut self,
