// Create session in tenant-a
    create_session(&db, "session-a1", "tenant-a", "Session A", None).await?;

// List sessions for tenant-b should NOT include tenant-a's sessions
    let tenant_b_sessions = db
        .list_chat_sessions("tenant-b", None, None, None, None)
        .await?;
    assert!(tenant_b_sessions.is_empty());

// List sessions for tenant-a should include its sessions
    let tenant_a_sessions = db
        .list_chat_sessions("tenant-a", None, None, None, None)
        .await?;
    assert_eq!(tenant_a_sessions.len(), 1);
    assert_eq!(tenant_a_sessions[0].id, "session-a1");

Ok(())
}

if path.is_dir() {
            let item = deploy_directory_adapter(path, &args, &backup_root, output).await?;
            items.push(item);
        } else if path
            .extension()
            .and_then(|e| e.to_str())
            .map(|e| e.eq_ignore_ascii_case("aos"))
            .unwrap_or(false)
        {
            let item = deploy_aos_adapter(path, &args, &backup_root, output).await?;
            items.push(item);
        } else {
            // Treat as weights file – deploy its parent directory
            if let Some(dir) = path.parent() {
                let item = deploy_directory_adapter(dir, &args, &backup_root, output).await?;
                items.push(item);
            } else {
                output.warning(format!(
                    "Cannot determine adapter directory for {}",
                    path.display()
                ));
            }
        }
    }

if output.is_json() {
        let result = DeployAdaptersResult {
            target_dir: args.adapters_dir.display().to_string(),
            dry_run: args.dry_run,
            backup_existing: args.backup_existing,
            items,
        };
        output.json(&result)?;
    } else if !output.is_quiet() {
        if args.dry_run {
            output.success("Dry run complete – no changes made");
        } else {
            output.success("Deployment complete");
        }
        if let Some(root) = &backup_root {
            output.kv("Backup dir", &root.display().to_string());
        }
    }

Ok(())
}

async fn deploy_directory_adapter(
    adapter_dir: &Path,
    args: &DeployAdaptersArgs,
    backup_root: &Option<PathBuf>,
    output: &OutputWriter,
) -> Result<DeployedItem> {
    let adapter_name = adapter_dir
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("unknown")
        .to_string();

if output.is_verbose() && !output.is_json() {
        output.info(format!("Deploying directory adapter: {}", adapter_name));
    }

let target_dir = args.adapters_dir.join(&adapter_name);
    let mut backed_up = false;

if target_dir.exists() && args.backup_existing {
        if let Some(root) = backup_root {
            let backup_path = root.join(&adapter_name);
            if args.dry_run {
                output.verbose(format!(
                    "[dry-run] would backup existing adapter {} -> {}",
                    target_dir.display(),
                    backup_path.display()
                ));
            } else {
                fs::create_dir_all(root)
                    .with_context(|| format!("creating backup dir {}", root.display()))?;
                fs::remove_dir_all(&backup_path).ok();
                fs::create_dir_all(backup_path.parent().unwrap_or_else(|| Path::new(".")))?;
                fs_extra::dir::copy(
                    &target_dir,
                    backup_path.parent().unwrap_or(root),
                    &fs_extra::dir::CopyOptions::new().content_only(false),
                )
                .with_context(|| {
                    format!(
                        "backing up existing adapter {} -> {}",
                        target_dir.display(),
                        backup_path.display()
                    )
                })?;
            }
            backed_up = true;
        }
    }

if args.dry_run {
        output.verbose(format!(
            "[dry-run] would copy dir {} -> {}",
            adapter_dir.display(),
            target_dir.display()
        ));
    } else {
        if target_dir.exists() {
            fs::remove_dir_all(&target_dir).ok();
        }
        fs::create_dir_all(target_dir.parent().unwrap_or_else(|| &args.adapters_dir))?;
        fs_extra::dir::copy(
            adapter_dir,
            &args.adapters_dir,
            &fs_extra::dir::CopyOptions::new().content_only(false),
        )
        .with_context(|| {
            format!(
                "copying adapter dir {} -> {}",
                adapter_dir.display(),
                args.adapters_dir.display()
            )
        })?;
    }

// Register via HTTP API (aosctl adapters register) using existing implementation
    let mut registered = false;
    if !args.dry_run {
        let register_args = crate::commands::adapters::RegisterArgs {
            path: target_dir.clone(),
            adapter_id: Some(adapter_name.clone()),
            name: None,
            rank: None,
            tier: None,
            base_url: "http://127.0.0.1:8080/api".to_string(),
        };
        let reg_output = OutputWriter::new(output.mode(), output.is_verbose());
        if crate::commands::adapters::run(
            crate::commands::adapters::AdaptersArgs {
                cmd: crate::commands::adapters::AdaptersCmd::Register(register_args),
            },
            &reg_output,
        )
        .await
        .is_ok()
        {
            registered = true;
        } else {
            output.warning(format!(
                "Adapter registration failed for {} (HTTP API)",
                adapter_name
            ));
        }
    }

Ok(DeployedItem {
        source: adapter_dir.display().to_string(),
        adapter_name,
        kind: "directory".to_string(),
        backed_up,
        registered,
    })
}

async fn deploy_aos_adapter(
    aos_file: &Path,
    args: &DeployAdaptersArgs,
    backup_root: &Option<PathBuf>,
    output: &OutputWriter,
) -> Result<DeployedItem> {
    let adapter_name = aos_file
        .file_stem()
        .and_then(|n| n.to_str())
        .unwrap_or("unknown")
        .to_string();

if output.is_verbose() && !output.is_json() {
        output.info(format!("Deploying .aos adapter: {}", adapter_name));
    }

//! CodeGraph - Deterministic Code Analysis
//!
//! This crate provides deterministic parsing and analysis of Rust codebases,
//! including call graph extraction, symbol type analysis, and semantic indexing.
//!
//! ## Features
//!
//! - Tree-sitter based AST parsing with deterministic output
//! - Call graph extraction with recursion and trait method linking
//! - Symbol type annotation and analysis
//! - SQLite persistence for efficient querying
//! - Deterministic hashing for reproducible builds

use adapteros_core::{B3Hash, Result};
use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;
use std::path::Path;

pub mod callgraph;
pub mod change_detector;
pub mod directory_analyzer;
pub mod framework_detector;
pub mod parsers;
pub mod sqlite;
pub mod types;

pub use callgraph::{CallEdge, CallGraph, CallGraphBuilder, ImportEdge};
pub use change_detector::{
    detect_recent_changes, ChangeType as DetectedChangeType, DetectedChange,
};
pub use directory_analyzer::{
    analyze_directory, DirectoryAnalysis, DirectorySymbol, DirectorySymbolKind,
};
pub use framework_detector::{detect_frameworks, DetectedFramework};
pub use parsers::{detect_language, parse_directory, parse_file, LanguageParser, ParserFactory};
pub use sqlite::{CodeGraphDb, DbConfig};
pub use types::{Language, SymbolId, SymbolKind, SymbolNode, TypeAnnotation, Visibility};

/// Main CodeGraph structure
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CodeGraph {
    /// Symbol nodes indexed by ID
    pub symbols: BTreeMap<SymbolId, SymbolNode>,
    /// Call graph edges
    pub call_graph: CallGraph,
    /// Content hash for determinism
    pub content_hash: B3Hash,
}

impl CodeGraph {
    /// Create a new empty CodeGraph
    pub fn new() -> Self {
        Self {
            symbols: BTreeMap::new(),
            call_graph: CallGraph::new(),
            content_hash: B3Hash::hash(b""),
        }
    }

/// Build CodeGraph from source directory
    pub async fn from_directory<P: AsRef<Path>>(
        source_dir: P,
        _db_config: Option<DbConfig>,
    ) -> Result<Self> {
        let mut builder = CallGraphBuilder::new();

// Parse all supported files in directory using multi-language parser
        let parse_results = parse_directory(source_dir.as_ref()).await?;

// Build symbol table and call graph
        for result in parse_results {
            builder.add_parse_result(result)?;
        }

let (call_graph, symbols) = builder.build_call_graph();

// Compute deterministic content hash
        let content_hash = Self::compute_content_hash(&symbols, &call_graph);

Ok(Self {
            symbols,
            call_graph,
            content_hash,
        })
    }

/// Compute deterministic content hash
    fn compute_content_hash(
        symbols: &BTreeMap<SymbolId, SymbolNode>,
        call_graph: &CallGraph,
    ) -> B3Hash {
        let mut hasher = blake3::Hasher::new();

// Hash symbols in deterministic order
        for (id, symbol) in symbols {
            hasher.update(id.as_bytes());
            hasher.update(symbol.name.as_bytes());
            hasher.update(symbol.kind.to_string().as_bytes());
            hasher.update(symbol.language.to_string().as_bytes());
            if let Some(ref type_annotation) = symbol.type_annotation {
                hasher.update(type_annotation.to_string().as_bytes());
            }
        }

// Hash call graph edges
        for edge in &call_graph.edges {
            hasher.update(edge.caller.as_bytes());
            hasher.update(edge.callee.as_bytes());
        }

// Hash import edges (cross-language dependencies)
        for edge in &call_graph.import_edges {
            hasher.update(edge.importer.as_bytes());
            hasher.update(edge.imported.as_bytes());
            hasher.update(edge.import_statement.as_bytes());
            hasher.update(edge.source_language.to_string().as_bytes());
            hasher.update(edge.target_language.to_string().as_bytes());
        }

B3Hash::from_bytes(hasher.finalize().into())
    }

/// Get symbol by ID
    pub fn get_symbol(&self, id: &SymbolId) -> Option<&SymbolNode> {
        self.symbols.get(id)
    }
